INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00345', 'A-1. EDD Claims Examiner', 'California Local Unique Compliance', 'California Local Unique', 'A-1. EDD Claims Examiner — Employment Development Department (EDD). **Codes:** Unemp. Ins. Code (UIC) div. 1-7; Cal. Code Regs. tit. 22 div. 1; Lab. Code 1088-1099. **Documents Audited:** UI claims determinations, disability insurance (SDI/PFL) approvals/denials, DE 2501 certifications, employer tax contribution filings (DE 9/DE 9C), notice of determination letters, overpayment assessments, appeal decisions, base period wage records, benefit audit worksheets, identity verification documents.', 'A-1. EDD Claims Examiner', 'Employment Development Department (EDD). **Codes:** Unemp. Ins. Code (UIC) div. 1-7; Cal. Code Regs. tit. 22 div. 1; Lab. Code 1088-1099. **Documents Audited:** UI claims determinations, disability insurance (SDI/PFL) approvals/denials, DE 2501 certifications, employer tax contribution filings (DE 9/DE 9C), notice of determination letters, overpayment assessments, appeal decisions, base period wage records, benefit audit worksheets, identity verification documents.', '', 'UI claims determinations, disability insurance (SDI/PFL) approvals/denials, DE 2501 certifications, employer tax contribution filings (DE 9/DE 9C), notice of determination letters, overpayment assessments, appeal decisions, base period wage records, benefit audit worksheets, identity verification documents.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00346', 'A-2. EDD Tax Auditor', 'California Local Unique Compliance', 'California Local Unique', 'A-2. EDD Tax Auditor — EDD Tax Branch. **Codes:** UIC 976-977, 986-986.1, 1088-1089; RTC 19542. **Documents Audited:** Employer payroll tax audit reports, worker classification determinations (ABC test per AB 5), quarterly contribution returns, penalty assessment notices, voluntary plan certifications, information-sharing agreements with FTB/IRS, jeopardy assessments.', 'A-2. EDD Tax Auditor', 'EDD Tax Branch. **Codes:** UIC 976-977, 986-986.1, 1088-1089; RTC 19542. **Documents Audited:** Employer payroll tax audit reports, worker classification determinations (ABC test per AB 5), quarterly contribution returns, penalty assessment notices, voluntary plan certifications, information-sharing agreements with FTB/IRS, jeopardy assessments.', '', 'Employer payroll tax audit reports, worker classification determinations (ABC test per AB 5), quarterly contribution returns, penalty assessment notices, voluntary plan certifications, information-sharing agreements with FTB/IRS, jeopardy assessments.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00347', 'A-3. CEC Energy Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-3. CEC Energy Analyst — California Energy Commission. **Codes:** PRC 25000-25986; Cal. Code Regs. tit. 20 1601-1609 (Title 24 Part 6 energy standards); PUC 454.5. **Documents Audited:** Building energy efficiency compliance certificates (CF-1R/CF-2R/CF-3R), power plant siting applications (AFC), renewable portfolio standard reports, integrated energy policy reports, appliance efficiency certifications, demand forecast documents, CEQA functional equivalency reviews, SB 100 compliance filings.', 'A-3. CEC Energy Analyst', 'California Energy Commission. **Codes:** PRC 25000-25986; Cal. Code Regs. tit. 20 1601-1609 (Title 24 Part 6 energy standards); PUC 454.5. **Documents Audited:** Building energy efficiency compliance certificates (CF-1R/CF-2R/CF-3R), power plant siting applications (AFC), renewable portfolio standard reports, integrated energy policy reports, appliance efficiency certifications, demand forecast documents, CEQA functional equivalency reviews, SB 100 compliance filings.', '', 'Building energy efficiency compliance certificates (CF-1R/CF-2R/CF-3R), power plant siting applications (AFC), renewable portfolio standard reports, integrated energy policy reports, appliance efficiency certifications, demand forecast documents, CEQA functional equivalency reviews, SB 100 compliance filings.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00348', 'A-4. CEC Siting Specialist', 'California Local Unique Compliance', 'California Local Unique', 'A-4. CEC Siting Specialist — California Energy Commission, Siting Division. **Codes:** PRC 25500-25542; Warren-Alquist Act; Cal. Code Regs. tit. 20 1701-1770. **Documents Audited:** Applications for certification (AFC) for thermal power plants 50MW+, compliance monitoring reports, facility amendment requests, small power plant exemption applications, transmission corridor designations, decommissioning plans.', 'A-4. CEC Siting Specialist', 'California Energy Commission, Siting Division. **Codes:** PRC 25500-25542; Warren-Alquist Act; Cal. Code Regs. tit. 20 1701-1770. **Documents Audited:** Applications for certification (AFC) for thermal power plants 50MW+, compliance monitoring reports, facility amendment requests, small power plant exemption applications, transmission corridor designations, decommissioning plans.', '', 'Applications for certification (AFC) for thermal power plants 50MW+, compliance monitoring reports, facility amendment requests, small power plant exemption applications, transmission corridor designations, decommissioning plans.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00349', 'A-5. FPPC Enforcement Counsel', 'California Local Unique Compliance', 'California Local Unique', 'A-5. FPPC Enforcement Counsel — Fair Political Practices Commission. **Codes:** Gov. Code 81000-91015 (Political Reform Act); Cal. Code Regs. tit. 2 18110-18997. **Documents Audited:** Campaign disclosure statements (Form 460/461/496/497), statements of economic interest (Form 700), lobbyist registration/reports (Form 601/602/603/625), enforcement complaint files, audit reports, advice letters, penalty assessments, behested payment reports (Form 803), slate mailer filings.', 'A-5. FPPC Enforcement Counsel', 'Fair Political Practices Commission. **Codes:** Gov. Code 81000-91015 (Political Reform Act); Cal. Code Regs. tit. 2 18110-18997. **Documents Audited:** Campaign disclosure statements (Form 460/461/496/497), statements of economic interest (Form 700), lobbyist registration/reports (Form 601/602/603/625), enforcement complaint files, audit reports, advice letters, penalty assessments, behested payment reports (Form 803), slate mailer filings.', '', 'Campaign disclosure statements (Form 460/461/496/497), statements of economic interest (Form 700), lobbyist registration/reports (Form 601/602/603/625), enforcement complaint files, audit reports, advice letters, penalty assessments, behested payment reports (Form 803), slate mailer filings.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00350', 'A-6. FPPC Filing Officer', 'California Local Unique Compliance', 'California Local Unique', 'A-6. FPPC Filing Officer — FPPC. **Codes:** Gov. Code 84100-84252, 87200-87210. **Documents Audited:** Form 700 (SEI) filings for completeness, campaign statement filing deadlines and amendments, late contribution/expenditure reports, electronic filing compliance, lobbyist employer quarterly reports, conflict-of-interest code reviews.', 'A-6. FPPC Filing Officer', 'FPPC. **Codes:** Gov. Code 84100-84252, 87200-87210. **Documents Audited:** Form 700 (SEI) filings for completeness, campaign statement filing deadlines and amendments, late contribution/expenditure reports, electronic filing compliance, lobbyist employer quarterly reports, conflict-of-interest code reviews.', '', 'Form 700 (SEI) filings for completeness, campaign statement filing deadlines and amendments, late contribution/expenditure reports, electronic filing compliance, lobbyist employer quarterly reports, conflict-of-interest code reviews.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00351', 'A-7. FTB Tax Auditor', 'California Local Unique Compliance', 'California Local Unique', 'A-7. FTB Tax Auditor — Franchise Tax Board. **Codes:** RTC 17001-24991 (Personal Income Tax Law), 23001-24691 (Corporation Tax Law); Cal. Code Regs. tit. 18. **Documents Audited:** Personal income tax returns (Form 540), corporate tax returns (Form 100), S-corp returns (Form 100S), partnership returns (Form 565), LLC returns (Form 568), notice of proposed assessment (NPA), protest decisions, Offer in Compromise files, abatement requests, residency determination packages, audit workpapers, collec', 'A-7. FTB Tax Auditor', 'Franchise Tax Board. **Codes:** RTC 17001-24991 (Personal Income Tax Law), 23001-24691 (Corporation Tax Law); Cal. Code Regs. tit. 18. **Documents Audited:** Personal income tax returns (Form 540), corporate tax returns (Form 100), S-corp returns (Form 100S), partnership returns (Form 565), LLC returns (Form 568), notice of proposed assessment (NPA), protest decisions, Offer in Compromise files, abatement requests, residency determination packages, audit workpapers, collections correspondence, a', '', 'Personal income tax returns (Form 540), corporate tax returns (Form 100), S-corp returns (Form 100S), partnership returns (Form 565), LLC returns (Form 568), notice of proposed assessment (NPA), protest decisions, Offer in Compromise files, abatement requests, residency determination packages, audit workpapers, collections correspondence, amnesty filings.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00352', 'A-8. FTB Collections Officer', 'California Local Unique Compliance', 'California Local Unique', 'A-8. FTB Collections Officer — Franchise Tax Board, Collections Division. **Codes:** RTC 19001-19780; Gov. Code 12419.5; CCP 706.070-706.077. **Documents Audited:** Earnings withholding orders, bank levies, liens (state tax liens filed with county recorder), offset notices (lottery/vendor intercepts), installment agreement documents, hardship determination files, interagency intercept notices (EDD/Controller).', 'A-8. FTB Collections Officer', 'Franchise Tax Board, Collections Division. **Codes:** RTC 19001-19780; Gov. Code 12419.5; CCP 706.070-706.077. **Documents Audited:** Earnings withholding orders, bank levies, liens (state tax liens filed with county recorder), offset notices (lottery/vendor intercepts), installment agreement documents, hardship determination files, interagency intercept notices (EDD/Controller).', '', 'Earnings withholding orders, bank levies, liens (state tax liens filed with county recorder), offset notices (lottery/vendor intercepts), installment agreement documents, hardship determination files, interagency intercept notices (EDD/Controller).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00353', 'A-9. Governor''s Legal Affairs Secretary', 'California Local Unique Compliance', 'California Local Unique', 'A-9. Governor''s Legal Affairs Secretary — Governor''s Office. **Codes:** Cal. Const. Art. V; Gov. Code 12000-12080; Gov. Code 11340-11361 (APA). **Documents Audited:** Executive orders, proclamations of emergency, extradition warrants, judicial appointment packages, bill signing statements, clemency/pardon applications, regulatory review memoranda, appointments to boards/commissions, State of Emergency declarations, budget proposals.', 'A-9. Governor''s Legal Affairs Secretary', 'Governor''s Office. **Codes:** Cal. Const. Art. V; Gov. Code 12000-12080; Gov. Code 11340-11361 (APA). **Documents Audited:** Executive orders, proclamations of emergency, extradition warrants, judicial appointment packages, bill signing statements, clemency/pardon applications, regulatory review memoranda, appointments to boards/commissions, State of Emergency declarations, budget proposals.', '', 'Executive orders, proclamations of emergency, extradition warrants, judicial appointment packages, bill signing statements, clemency/pardon applications, regulatory review memoranda, appointments to boards/commissions, State of Emergency declarations, budget proposals.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00354', 'A-10. CDI Insurance Examiner', 'California Local Unique Compliance', 'California Local Unique', 'A-10. CDI Insurance Examiner — California Department of Insurance. **Codes:** Ins. Code 1-16111; Cal. Code Regs. tit. 10. **Documents Audited:** Insurance rate filings, policy form approvals, annual financial statements (statutory accounting), market conduct examination reports, complaint files, license applications, surplus line broker filings, insurer solvency reports, advertising review files, claims handling practice audits (Fair Claims Settlement Practices Regulations tit. 10 2695.1-2695.17', 'A-10. CDI Insurance Examiner', 'California Department of Insurance. **Codes:** Ins. Code 1-16111; Cal. Code Regs. tit. 10. **Documents Audited:** Insurance rate filings, policy form approvals, annual financial statements (statutory accounting), market conduct examination reports, complaint files, license applications, surplus line broker filings, insurer solvency reports, advertising review files, claims handling practice audits (Fair Claims Settlement Practices Regulations tit. 10 2695.1-2695.17).', '', 'Insurance rate filings, policy form approvals, annual financial statements (statutory accounting), market conduct examination reports, complaint files, license applications, surplus line broker filings, insurer solvency reports, advertising review files, claims handling practice audits (Fair Claims Settlement Practices Regulations tit. 10 2695.1-2695.17).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00355', 'A-11. CDI Fraud Investigator', 'California Local Unique Compliance', 'California Local Unique', 'A-11. CDI Fraud Investigator — CDI Fraud Division. **Codes:** Ins. Code 1871-1879.8 (fraud provisions); Pen. Code 548-551. **Documents Audited:** Suspected fraudulent claim investigations (SIU referrals), mandatory fraud reporting compliance (annual SIU reports), anti-fraud plan filings, investigation case files, referrals to DA, workers'' comp fraud referrals, premium fraud assessments.', 'A-11. CDI Fraud Investigator', 'CDI Fraud Division. **Codes:** Ins. Code 1871-1879.8 (fraud provisions); Pen. Code 548-551. **Documents Audited:** Suspected fraudulent claim investigations (SIU referrals), mandatory fraud reporting compliance (annual SIU reports), anti-fraud plan filings, investigation case files, referrals to DA, workers'' comp fraud referrals, premium fraud assessments.', '', 'Suspected fraudulent claim investigations (SIU referrals), mandatory fraud reporting compliance (annual SIU reports), anti-fraud plan filings, investigation case files, referrals to DA, workers'' comp fraud referrals, premium fraud assessments.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00356', 'A-12. Judicial Council Staff Attorney', 'California Local Unique Compliance', 'California Local Unique', 'A-12. Judicial Council Staff Attorney — Judicial Council of California. **Codes:** Cal. Const. Art. VI sec. 6; Cal. Rules of Court 10.1-10.1030; Gov. Code 68500-68651. **Documents Audited:** Court administration reports, mandatory judicial branch statistical reports (JBSIS), case management system audits, court interpreter certification records, judicial performance evaluations, court facility construction/renovation plans, Judicial Council forms (500+ mandatory forms), trial court budget alloca', 'A-12. Judicial Council Staff Attorney', 'Judicial Council of California. **Codes:** Cal. Const. Art. VI sec. 6; Cal. Rules of Court 10.1-10.1030; Gov. Code 68500-68651. **Documents Audited:** Court administration reports, mandatory judicial branch statistical reports (JBSIS), case management system audits, court interpreter certification records, judicial performance evaluations, court facility construction/renovation plans, Judicial Council forms (500+ mandatory forms), trial court budget allocations, language access plans.', '', 'Court administration reports, mandatory judicial branch statistical reports (JBSIS), case management system audits, court interpreter certification records, judicial performance evaluations, court facility construction/renovation plans, Judicial Council forms (500+ mandatory forms), trial court budget allocations, language access plans.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00357', 'A-13. Judicial Council Rules Attorney', 'California Local Unique Compliance', 'California Local Unique', 'A-13. Judicial Council Rules Attorney — Judicial Council, Rules Committee. **Codes:** Cal. Rules of Court 1.1-9.50; CCP 575-576; Gov. Code 68070-68073. **Documents Audited:** Proposed rule amendments and public comments, invitation-to-comment responses, rules implementation memoranda, advisory committee reports, emergency rule adoptions, form approval packages, local court rule reviews for consistency with statewide rules.', 'A-13. Judicial Council Rules Attorney', 'Judicial Council, Rules Committee. **Codes:** Cal. Rules of Court 1.1-9.50; CCP 575-576; Gov. Code 68070-68073. **Documents Audited:** Proposed rule amendments and public comments, invitation-to-comment responses, rules implementation memoranda, advisory committee reports, emergency rule adoptions, form approval packages, local court rule reviews for consistency with statewide rules.', '', 'Proposed rule amendments and public comments, invitation-to-comment responses, rules implementation memoranda, advisory committee reports, emergency rule adoptions, form approval packages, local court rule reviews for consistency with statewide rules.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00358', 'A-14. Legislative Counsel', 'California Local Unique Compliance', 'California Local Unique', 'A-14. Legislative Counsel — California Legislature / Office of Legislative Counsel. **Codes:** Gov. Code 10200-10290; Cal. Const. Art. IV. **Documents Audited:** Bill drafts and amendments, legislative counsel opinions, enrolled bill reports, constitutional analyses, statutory revision memoranda, committee analyses, legislative intent documentation, chaptering of enacted statutes, urgency clause certifications.', 'A-14. Legislative Counsel', 'California Legislature / Office of Legislative Counsel. **Codes:** Gov. Code 10200-10290; Cal. Const. Art. IV. **Documents Audited:** Bill drafts and amendments, legislative counsel opinions, enrolled bill reports, constitutional analyses, statutory revision memoranda, committee analyses, legislative intent documentation, chaptering of enacted statutes, urgency clause certifications.', '', 'Bill drafts and amendments, legislative counsel opinions, enrolled bill reports, constitutional analyses, statutory revision memoranda, committee analyses, legislative intent documentation, chaptering of enacted statutes, urgency clause certifications.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00359', 'A-15. Legislative Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-15. Legislative Analyst — Legislative Analyst''s Office (LAO). **Codes:** Gov. Code 9140-9149. **Documents Audited:** Fiscal impact analyses of proposed legislation, annual budget analyses ("Analysis of the Budget Bill"), ballot measure analyses, policy briefs, long-term fiscal outlook reports, CalFacts publications, initiative fiscal estimates for Attorney General.', 'A-15. Legislative Analyst', 'Legislative Analyst''s Office (LAO). **Codes:** Gov. Code 9140-9149. **Documents Audited:** Fiscal impact analyses of proposed legislation, annual budget analyses ("Analysis of the Budget Bill"), ballot measure analyses, policy briefs, long-term fiscal outlook reports, CalFacts publications, initiative fiscal estimates for Attorney General.', '', 'Fiscal impact analyses of proposed legislation, annual budget analyses ("Analysis of the Budget Bill"), ballot measure analyses, policy briefs, long-term fiscal outlook reports, CalFacts publications, initiative fiscal estimates for Attorney General.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00360', 'A-16. Cal/OSHA Compliance Officer (Safety)', 'California Local Unique Compliance', 'California Local Unique', 'A-16. Cal/OSHA Compliance Officer (Safety) — Division of Occupational Safety and Health (Cal/OSHA). **Codes:** Lab. Code 6300-6719; Cal. Code Regs. tit. 8 (General Industry Safety Orders, Construction Safety Orders). **Documents Audited:** Workplace inspection reports, citations and penalty assessments, Injury and Illness Prevention Program (IIPP) documents (Lab. Code 6401.7), employer accident/illness reports (Form 5020), appeal files before OSHAB, variance applications, abatement verification ', 'A-16. Cal/OSHA Compliance Officer (Safety)', 'Division of Occupational Safety and Health (Cal/OSHA). **Codes:** Lab. Code 6300-6719; Cal. Code Regs. tit. 8 (General Industry Safety Orders, Construction Safety Orders). **Documents Audited:** Workplace inspection reports, citations and penalty assessments, Injury and Illness Prevention Program (IIPP) documents (Lab. Code 6401.7), employer accident/illness reports (Form 5020), appeal files before OSHAB, variance applications, abatement verification documents, serious injury/fatality investigat', '', 'Workplace inspection reports, citations and penalty assessments, Injury and Illness Prevention Program (IIPP) documents (Lab. Code 6401.7), employer accident/illness reports (Form 5020), appeal files before OSHAB, variance applications, abatement verification documents, serious injury/fatality investigation reports, heat illness prevention plans, COVID-19 prevention plans.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00361', 'A-17. Cal/OSHA Industrial Hygienist', 'California Local Unique Compliance', 'California Local Unique', 'A-17. Cal/OSHA Industrial Hygienist — Cal/OSHA. **Codes:** Lab. Code 6350-6356, 142.3; Cal. Code Regs. tit. 8 5139-5223 (hazardous substances). **Documents Audited:** Exposure monitoring reports, permissible exposure limit (PEL) compliance records, respiratory protection program documents, hazard communication program audits, laboratory chemical hygiene plans, lead/asbestos exposure assessments, biological monitoring results.', 'A-17. Cal/OSHA Industrial Hygienist', 'Cal/OSHA. **Codes:** Lab. Code 6350-6356, 142.3; Cal. Code Regs. tit. 8 5139-5223 (hazardous substances). **Documents Audited:** Exposure monitoring reports, permissible exposure limit (PEL) compliance records, respiratory protection program documents, hazard communication program audits, laboratory chemical hygiene plans, lead/asbestos exposure assessments, biological monitoring results.', '', 'Exposure monitoring reports, permissible exposure limit (PEL) compliance records, respiratory protection program documents, hazard communication program audits, laboratory chemical hygiene plans, lead/asbestos exposure assessments, biological monitoring results.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00362', 'A-18. Secretary of State Elections Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-18. Secretary of State Elections Analyst — California Secretary of State. **Codes:** Elec. Code 1-23003; Gov. Code 6253.5 (public records). **Documents Audited:** Candidate filing documents, ballot measure submissions, initiative petition signature verifications, campaign finance filings (mirror of FPPC), election night reporting, voting system certifications, county election plans, voter registration database audits, conditional voter registration compliance.', 'A-18. Secretary of State Elections Analyst', 'California Secretary of State. **Codes:** Elec. Code 1-23003; Gov. Code 6253.5 (public records). **Documents Audited:** Candidate filing documents, ballot measure submissions, initiative petition signature verifications, campaign finance filings (mirror of FPPC), election night reporting, voting system certifications, county election plans, voter registration database audits, conditional voter registration compliance.', '', 'Candidate filing documents, ballot measure submissions, initiative petition signature verifications, campaign finance filings (mirror of FPPC), election night reporting, voting system certifications, county election plans, voter registration database audits, conditional voter registration compliance.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00363', 'A-19. Secretary of State Business Programs Examiner', 'California Local Unique Compliance', 'California Local Unique', 'A-19. Secretary of State Business Programs Examiner — Secretary of State, Business Programs Division. **Codes:** Corp. Code 100-2319 (corporations), 15900-16962 (partnerships/LLCs), 17701.01-17713.13 (LLCs); Com. Code 9501-9528 (UCC filings). **Documents Audited:** Articles of incorporation/organization, statements of information (annual/biennial), UCC financing statements, notary public commission applications and journals, trademark/service mark registrations, domestic partnership registration', 'A-19. Secretary of State Business Programs Examiner', 'Secretary of State, Business Programs Division. **Codes:** Corp. Code 100-2319 (corporations), 15900-16962 (partnerships/LLCs), 17701.01-17713.13 (LLCs); Com. Code 9501-9528 (UCC filings). **Documents Audited:** Articles of incorporation/organization, statements of information (annual/biennial), UCC financing statements, notary public commission applications and journals, trademark/service mark registrations, domestic partnership registrations, apostille/authentication requests, business entity ', '', 'Articles of incorporation/organization, statements of information (annual/biennial), UCC financing statements, notary public commission applications and journals, trademark/service mark registrations, domestic partnership registrations, apostille/authentication requests, business entity mergers/dissolutions.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00364', 'A-20. State Water Board Water Quality Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-20. State Water Board Water Quality Analyst — State Water Resources Control Board (SWRCB). **Codes:** Wat. Code 13000-13999; HSC 116270-116755 (Safe Drinking Water Act); PRC 21000+ (CEQA nexus). **Documents Audited:** NPDES permits and compliance reports, waste discharge requirements (WDRs), water quality monitoring reports, TMDLs, stormwater pollution prevention plans (SWPPPs), underground storage tank cleanup fund files, 303(d) impaired waters listings, basin plan amendments, water recycling', 'A-20. State Water Board Water Quality Analyst', 'State Water Resources Control Board (SWRCB). **Codes:** Wat. Code 13000-13999; HSC 116270-116755 (Safe Drinking Water Act); PRC 21000+ (CEQA nexus). **Documents Audited:** NPDES permits and compliance reports, waste discharge requirements (WDRs), water quality monitoring reports, TMDLs, stormwater pollution prevention plans (SWPPPs), underground storage tank cleanup fund files, 303(d) impaired waters listings, basin plan amendments, water recycling permits, sanitary sewer system management plans', '', 'NPDES permits and compliance reports, waste discharge requirements (WDRs), water quality monitoring reports, TMDLs, stormwater pollution prevention plans (SWPPPs), underground storage tank cleanup fund files, 303(d) impaired waters listings, basin plan amendments, water recycling permits, sanitary sewer system management plans.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00365', 'A-21. State Water Board Water Rights Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-21. State Water Board Water Rights Analyst — SWRCB, Division of Water Rights. **Codes:** Wat. Code 1200-1851; Cal. Code Regs. tit. 23 div. 3. **Documents Audited:** Water rights applications and permits, statements of diversion, water rights licenses, change petitions, water transfer approvals, instream flow dedications, curtailment notices during drought, water availability analyses, appropriative rights protests and hearings.', 'A-21. State Water Board Water Rights Analyst', 'SWRCB, Division of Water Rights. **Codes:** Wat. Code 1200-1851; Cal. Code Regs. tit. 23 div. 3. **Documents Audited:** Water rights applications and permits, statements of diversion, water rights licenses, change petitions, water transfer approvals, instream flow dedications, curtailment notices during drought, water availability analyses, appropriative rights protests and hearings.', '', 'Water rights applications and permits, statements of diversion, water rights licenses, change petitions, water transfer approvals, instream flow dedications, curtailment notices during drought, water availability analyses, appropriative rights protests and hearings.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00366', 'A-22. State Treasurer Debt Manager', 'California Local Unique Compliance', 'California Local Unique', 'A-22. State Treasurer Debt Manager — California State Treasurer''s Office (STO). **Codes:** Gov. Code 16300-16430, 5000-5980 (Marks-Roos); Cal. Const. Art. XVI. **Documents Audited:** General obligation bond issuance documents, revenue bond official statements, Marks-Roos authority bond filings, CDIAC (California Debt and Investment Advisory Commission) annual debt reports, pooled money investment reports (PMIA), tax credit allocations (LIHTC via CTCAC), CalABLE program compliance, ScholarShare p', 'A-22. State Treasurer Debt Manager', 'California State Treasurer''s Office (STO). **Codes:** Gov. Code 16300-16430, 5000-5980 (Marks-Roos); Cal. Const. Art. XVI. **Documents Audited:** General obligation bond issuance documents, revenue bond official statements, Marks-Roos authority bond filings, CDIAC (California Debt and Investment Advisory Commission) annual debt reports, pooled money investment reports (PMIA), tax credit allocations (LIHTC via CTCAC), CalABLE program compliance, ScholarShare program audits, conduit bond post-issu', '', 'General obligation bond issuance documents, revenue bond official statements, Marks-Roos authority bond filings, CDIAC (California Debt and Investment Advisory Commission) annual debt reports, pooled money investment reports (PMIA), tax credit allocations (LIHTC via CTCAC), CalABLE program compliance, ScholarShare program audits, conduit bond post-issuance compliance.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00367', 'A-23. CDIAC Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-23. CDIAC Analyst — California Debt and Investment Advisory Commission (under Treasurer). **Codes:** Gov. Code 8855-8859.7. **Documents Audited:** Report of proposed debt issuance (filed by all public agencies), report of final sale, annual debt transparency reports, Mello-Roos and marks-roos bond filings, refunding savings analyses, continuing disclosure compliance reviews.', 'A-23. CDIAC Analyst', 'California Debt and Investment Advisory Commission (under Treasurer). **Codes:** Gov. Code 8855-8859.7. **Documents Audited:** Report of proposed debt issuance (filed by all public agencies), report of final sale, annual debt transparency reports, Mello-Roos and marks-roos bond filings, refunding savings analyses, continuing disclosure compliance reviews.', '', 'Report of proposed debt issuance (filed by all public agencies), report of final sale, annual debt transparency reports, Mello-Roos and marks-roos bond filings, refunding savings analyses, continuing disclosure compliance reviews.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00368', 'B-1. County Supervisor', 'California Local Unique Compliance', 'California Local Unique', 'B-1. County Supervisor — County Board of Supervisors. **Codes:** Gov. Code 25000-25009, 23000-23027; Cal. Const. Art. XI sec. 1. **Documents Audited:** Board resolutions and ordinances, budget adoption documents, general plan adoption records, county formation/boundary documents, franchise agreements, legislative body minutes, Brown Act compliance records, CEQA findings for county projects, intergovernmental agreements, emergency declarations.', 'B-1. County Supervisor', 'County Board of Supervisors. **Codes:** Gov. Code 25000-25009, 23000-23027; Cal. Const. Art. XI sec. 1. **Documents Audited:** Board resolutions and ordinances, budget adoption documents, general plan adoption records, county formation/boundary documents, franchise agreements, legislative body minutes, Brown Act compliance records, CEQA findings for county projects, intergovernmental agreements, emergency declarations.', '', 'Board resolutions and ordinances, budget adoption documents, general plan adoption records, county formation/boundary documents, franchise agreements, legislative body minutes, Brown Act compliance records, CEQA findings for county projects, intergovernmental agreements, emergency declarations.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00369', 'B-2. County Clerk-Recorder', 'California Local Unique Compliance', 'California Local Unique', 'B-2. County Clerk-Recorder — County Clerk/Recorder''s Office. **Codes:** Gov. Code 26800-26832 (clerk), 27201-27383 (recorder); Elec. Code 1000-1501; Fam. Code 350-500 (marriage). **Documents Audited:** Real property deeds and liens, vital records (birth/death/marriage certificates), fictitious business name statements, notary bonds, maps and surveys, oaths of office, election official certifications, recording fee schedules, document indexing and retrieval standards, California Uniform Commercia', 'B-2. County Clerk-Recorder', 'County Clerk/Recorder''s Office. **Codes:** Gov. Code 26800-26832 (clerk), 27201-27383 (recorder); Elec. Code 1000-1501; Fam. Code 350-500 (marriage). **Documents Audited:** Real property deeds and liens, vital records (birth/death/marriage certificates), fictitious business name statements, notary bonds, maps and surveys, oaths of office, election official certifications, recording fee schedules, document indexing and retrieval standards, California Uniform Commercial Code filings (county level)', '', 'Real property deeds and liens, vital records (birth/death/marriage certificates), fictitious business name statements, notary bonds, maps and surveys, oaths of office, election official certifications, recording fee schedules, document indexing and retrieval standards, California Uniform Commercial Code filings (county level), marriage license applications, passport applications.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00370', 'B-3. County Assessor', 'California Local Unique Compliance', 'California Local Unique', 'B-3. County Assessor — County Assessor''s Office. **Codes:** RTC 75-469.5 (Prop 13 assessment); Cal. Const. Art. XIIIA; Cal. Code Regs. tit. 18 1-1005. **Documents Audited:** Property assessment rolls, change of ownership statements, new construction assessments, exemption claims (homeowner''s, veteran''s, church, welfare), Prop 8 temporary decline-in-value reviews, Prop 13 base year value calculations, supplemental/escape assessments, possessory interest valuations, business personal property stat', 'B-3. County Assessor', 'County Assessor''s Office. **Codes:** RTC 75-469.5 (Prop 13 assessment); Cal. Const. Art. XIIIA; Cal. Code Regs. tit. 18 1-1005. **Documents Audited:** Property assessment rolls, change of ownership statements, new construction assessments, exemption claims (homeowner''s, veteran''s, church, welfare), Prop 8 temporary decline-in-value reviews, Prop 13 base year value calculations, supplemental/escape assessments, possessory interest valuations, business personal property statements (Form 571), Will', '', 'Property assessment rolls, change of ownership statements, new construction assessments, exemption claims (homeowner''s, veteran''s, church, welfare), Prop 8 temporary decline-in-value reviews, Prop 13 base year value calculations, supplemental/escape assessments, possessory interest valuations, business personal property statements (Form 571), Williamson Act valuations, assessment appeal hearing records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00371', 'B-4. County Treasurer-Tax Collector', 'California Local Unique Compliance', 'California Local Unique', 'B-4. County Treasurer-Tax Collector — County Treasurer-Tax Collector Office. **Codes:** RTC 2601-4377 (tax collection); Gov. Code 27000-27092 (treasurer). **Documents Audited:** Tax bills (secured/unsecured), delinquent property tax rolls, tax sale certificates, Teeter Plan participation documents, county investment pool reports (quarterly per Gov. Code 53646), installment plan agreements, treasury investment policy, redemption records, transient occupancy tax (TOT) filings, assessment district ', 'B-4. County Treasurer-Tax Collector', 'County Treasurer-Tax Collector Office. **Codes:** RTC 2601-4377 (tax collection); Gov. Code 27000-27092 (treasurer). **Documents Audited:** Tax bills (secured/unsecured), delinquent property tax rolls, tax sale certificates, Teeter Plan participation documents, county investment pool reports (quarterly per Gov. Code 53646), installment plan agreements, treasury investment policy, redemption records, transient occupancy tax (TOT) filings, assessment district levy calculations.', '', 'Tax bills (secured/unsecured), delinquent property tax rolls, tax sale certificates, Teeter Plan participation documents, county investment pool reports (quarterly per Gov. Code 53646), installment plan agreements, treasury investment policy, redemption records, transient occupancy tax (TOT) filings, assessment district levy calculations.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00372', 'B-5. County Counsel', 'California Local Unique Compliance', 'California Local Unique', 'B-5. County Counsel — County Counsel''s Office. **Codes:** Gov. Code 27642-27650; county charter. **Documents Audited:** Legal opinions to board/departments, conflict-of-interest analyses, ordinance/resolution legal review, litigation status reports, settlement agreements, Brown Act compliance opinions, CEQA sufficiency reviews, contract review memoranda, claims filed against county (Gov. Code 900-915.4), public records request legal determinations, grand jury response reviews.', 'B-5. County Counsel', 'County Counsel''s Office. **Codes:** Gov. Code 27642-27650; county charter. **Documents Audited:** Legal opinions to board/departments, conflict-of-interest analyses, ordinance/resolution legal review, litigation status reports, settlement agreements, Brown Act compliance opinions, CEQA sufficiency reviews, contract review memoranda, claims filed against county (Gov. Code 900-915.4), public records request legal determinations, grand jury response reviews.', '', 'Legal opinions to board/departments, conflict-of-interest analyses, ordinance/resolution legal review, litigation status reports, settlement agreements, Brown Act compliance opinions, CEQA sufficiency reviews, contract review memoranda, claims filed against county (Gov. Code 900-915.4), public records request legal determinations, grand jury response reviews.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00373', 'B-6. District Attorney', 'California Local Unique Compliance', 'California Local Unique', 'B-6. District Attorney — County District Attorney''s Office. **Codes:** Gov. Code 26500-26535; Pen. Code 681-694 (prosecution duties), 832.7 (disclosure), 1001-1001.95 (diversion). **Documents Audited:** Charging documents (complaints, informations, indictments), plea agreements, victim restitution orders, asset forfeiture filings, Brady disclosure logs, gang enhancement filings, three strikes allegations, Marsy''s Law victim notification records, consumer protection enforcement files, worker misc', 'B-6. District Attorney', 'County District Attorney''s Office. **Codes:** Gov. Code 26500-26535; Pen. Code 681-694 (prosecution duties), 832.7 (disclosure), 1001-1001.95 (diversion). **Documents Audited:** Charging documents (complaints, informations, indictments), plea agreements, victim restitution orders, asset forfeiture filings, Brady disclosure logs, gang enhancement filings, three strikes allegations, Marsy''s Law victim notification records, consumer protection enforcement files, worker misclassification referrals, ', '', 'Charging documents (complaints, informations, indictments), plea agreements, victim restitution orders, asset forfeiture filings, Brady disclosure logs, gang enhancement filings, three strikes allegations, Marsy''s Law victim notification records, consumer protection enforcement files, worker misclassification referrals, real estate fraud prosecution files, elder abuse prosecution files, environmental crime prosecutions.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00374', 'B-7. Public Defender', 'California Local Unique Compliance', 'California Local Unique', 'B-7. Public Defender — County Public Defender''s Office. **Codes:** Gov. Code 27700-27712; Pen. Code 987-987.9; Cal. Const. Art. I sec. 15. **Documents Audited:** Indigency declarations, appointment orders, case disposition records, caseload statistics (per ABA standards), conflict panel referrals, post-conviction relief petitions (Pen. Code 1170.95/1172.6, Prop 47/57 resentencing), habeas corpus petitions, client communication logs, investigation expense authorizations, appellate transfer files,', 'B-7. Public Defender', 'County Public Defender''s Office. **Codes:** Gov. Code 27700-27712; Pen. Code 987-987.9; Cal. Const. Art. I sec. 15. **Documents Audited:** Indigency declarations, appointment orders, case disposition records, caseload statistics (per ABA standards), conflict panel referrals, post-conviction relief petitions (Pen. Code 1170.95/1172.6, Prop 47/57 resentencing), habeas corpus petitions, client communication logs, investigation expense authorizations, appellate transfer files, juvenile delinquency r', '', 'Indigency declarations, appointment orders, case disposition records, caseload statistics (per ABA standards), conflict panel referrals, post-conviction relief petitions (Pen. Code 1170.95/1172.6, Prop 47/57 resentencing), habeas corpus petitions, client communication logs, investigation expense authorizations, appellate transfer files, juvenile delinquency representation records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00375', 'B-8. Sheriff', 'California Local Unique Compliance', 'California Local Unique', 'B-8. Sheriff — County Sheriff''s Department. **Codes:** Gov. Code 26600-26664; Pen. Code 830.1, 832, 13519-13519.14; Cal. Code Regs. tit. 15 (jails). **Documents Audited:** Arrest reports, booking records, use-of-force reports (SB 1421/AB 748 disclosure), body-worn camera policies, jail inspection reports (BSCC tit. 15/tit. 24), civil process service records, coroner''s investigation reports, sex offender registration (Pen. Code 290), CLETS access logs, RIPA stop data reports, concealed carry weap', 'B-8. Sheriff', 'County Sheriff''s Department. **Codes:** Gov. Code 26600-26664; Pen. Code 830.1, 832, 13519-13519.14; Cal. Code Regs. tit. 15 (jails). **Documents Audited:** Arrest reports, booking records, use-of-force reports (SB 1421/AB 748 disclosure), body-worn camera policies, jail inspection reports (BSCC tit. 15/tit. 24), civil process service records, coroner''s investigation reports, sex offender registration (Pen. Code 290), CLETS access logs, RIPA stop data reports, concealed carry weapon (CCW) permit', '', 'Arrest reports, booking records, use-of-force reports (SB 1421/AB 748 disclosure), body-worn camera policies, jail inspection reports (BSCC tit. 15/tit. 24), civil process service records, coroner''s investigation reports, sex offender registration (Pen. Code 290), CLETS access logs, RIPA stop data reports, concealed carry weapon (CCW) permit applications, mutual aid agreements, custodial death reports, internal affairs investigation files.');
