INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00377', 'B-10. County Health Officer', 'California Local Unique Compliance', 'California Local Unique', 'B-10. County Health Officer — County Health Department. **Codes:** HSC 101000-101475 (local health jurisdiction); HSC 120100-120580 (communicable disease); Cal. Code Regs. tit. 17. **Documents Audited:** Communicable disease reports, public health emergency orders, restaurant/food facility inspection reports (CalCode/HSC 113700+), body art facility permits, medical waste generator permits, birth/death certificates (vital statistics), immunization compliance reports (schools), environmental healt', 'B-10. County Health Officer', 'County Health Department. **Codes:** HSC 101000-101475 (local health jurisdiction); HSC 120100-120580 (communicable disease); Cal. Code Regs. tit. 17. **Documents Audited:** Communicable disease reports, public health emergency orders, restaurant/food facility inspection reports (CalCode/HSC 113700+), body art facility permits, medical waste generator permits, birth/death certificates (vital statistics), immunization compliance reports (schools), environmental health permits, tobacco retailer li', '', 'Communicable disease reports, public health emergency orders, restaurant/food facility inspection reports (CalCode/HSC 113700+), body art facility permits, medical waste generator permits, birth/death certificates (vital statistics), immunization compliance reports (schools), environmental health permits, tobacco retailer licenses, well permits, septic system permits, water quality sampling results, health officer orders of quarantine/isolation.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00378', 'B-11. County Social Services Eligibility Worker', 'California Local Unique Compliance', 'California Local Unique', 'B-11. County Social Services Eligibility Worker — County Department of Social Services (DSS). **Codes:** WIC 10000-18999 (CalWORKs), 14000-14199 (Medi-Cal), 18900-18927 (CalFresh); 42 USC 601+ (TANF federal); Cal. Code Regs. tit. 22 div. 3. **Documents Audited:** CalWORKs applications and redeterminations, CalFresh (SNAP) eligibility worksheets, Medi-Cal eligibility determinations (MAGI and non-MAGI), income verification documents, welfare-to-work participation records (WTW 2/WTW 73), overpaymen', 'B-11. County Social Services Eligibility Worker', 'County Department of Social Services (DSS). **Codes:** WIC 10000-18999 (CalWORKs), 14000-14199 (Medi-Cal), 18900-18927 (CalFresh); 42 USC 601+ (TANF federal); Cal. Code Regs. tit. 22 div. 3. **Documents Audited:** CalWORKs applications and redeterminations, CalFresh (SNAP) eligibility worksheets, Medi-Cal eligibility determinations (MAGI and non-MAGI), income verification documents, welfare-to-work participation records (WTW 2/WTW 73), overpayment/underpayment claims, fair hearing requests, coun', '', 'CalWORKs applications and redeterminations, CalFresh (SNAP) eligibility worksheets, Medi-Cal eligibility determinations (MAGI and non-MAGI), income verification documents, welfare-to-work participation records (WTW 2/WTW 73), overpayment/underpayment claims, fair hearing requests, county self-assessment reviews (CalWORKs Outcomes), In-Home Supportive Services (IHSS) assessments, General Assistance/General Relief applications.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00379', 'B-12. County Child Welfare Social Worker', 'California Local Unique Compliance', 'California Local Unique', 'B-12. County Child Welfare Social Worker — County Child Welfare Services (CPS/DCFS). **Codes:** WIC 300-395 (dependency jurisdiction), 16500-16522 (child welfare services); Pen. Code 11164-11174.3 (CANRA mandatory reporting); Cal. Code Regs. tit. 22 div. 2. **Documents Audited:** Child abuse/neglect referrals (8-583 hotline reports), safety and risk assessments (SDM tool), detention reports, jurisdiction/disposition reports (JV-320/JV-321), case plans (WIC 16501.1), court reports for review hear', 'B-12. County Child Welfare Social Worker', 'County Child Welfare Services (CPS/DCFS). **Codes:** WIC 300-395 (dependency jurisdiction), 16500-16522 (child welfare services); Pen. Code 11164-11174.3 (CANRA mandatory reporting); Cal. Code Regs. tit. 22 div. 2. **Documents Audited:** Child abuse/neglect referrals (8-583 hotline reports), safety and risk assessments (SDM tool), detention reports, jurisdiction/disposition reports (JV-320/JV-321), case plans (WIC 16501.1), court reports for review hearings, family reunification/maintenance serv', '', 'Child abuse/neglect referrals (8-583 hotline reports), safety and risk assessments (SDM tool), detention reports, jurisdiction/disposition reports (JV-320/JV-321), case plans (WIC 16501.1), court reports for review hearings, family reunification/maintenance service logs, ICPC interstate placement requests, adoption assessment reports, independent living program plans (ILP/THP+), placement change notifications, CACI index notifications, mandated reporter compliance files.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00380', 'B-13. County Behavioral Health Director', 'California Local Unique Compliance', 'California Local Unique', 'B-13. County Behavioral Health Director — County Department of Behavioral Health/Mental Health. **Codes:** WIC 5000-5120 (Short-Doyle), 5150-5157 (LPS Act involuntary holds), 5600-5604.5 (MHSA/Prop 63); HSC 1250.2. **Documents Audited:** Mental Health Services Act (MHSA) annual revenue/expenditure reports, 5150/5250/5270 involuntary hold documentation, capacity declarations, patients'' rights advocate reports, Mental Health Plan (MHP) compliance reviews (DHCS), Medi-Cal specialty mental health se', 'B-13. County Behavioral Health Director', 'County Department of Behavioral Health/Mental Health. **Codes:** WIC 5000-5120 (Short-Doyle), 5150-5157 (LPS Act involuntary holds), 5600-5604.5 (MHSA/Prop 63); HSC 1250.2. **Documents Audited:** Mental Health Services Act (MHSA) annual revenue/expenditure reports, 5150/5250/5270 involuntary hold documentation, capacity declarations, patients'' rights advocate reports, Mental Health Plan (MHP) compliance reviews (DHCS), Medi-Cal specialty mental health services claims, Full Service Partnership (F', '', 'Mental Health Services Act (MHSA) annual revenue/expenditure reports, 5150/5250/5270 involuntary hold documentation, capacity declarations, patients'' rights advocate reports, Mental Health Plan (MHP) compliance reviews (DHCS), Medi-Cal specialty mental health services claims, Full Service Partnership (FSP) outcome data, community program planning documents, substance use disorder (SUD) treatment authorization requests, Drug Medi-Cal organized delivery system waiver compliance, conservatorship investigation reports (LPS), Laura''s Law/AOT petitions.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00381', 'B-14. City Council Member', 'California Local Unique Compliance', 'California Local Unique', 'B-14. City Council Member — City Council (general law or charter city). **Codes:** Gov. Code 34000-45343 (Govt of Cities); Cal. Const. Art. XI sec. 3-5. **Documents Audited:** City ordinances and resolutions, general plan adoption/amendments, budget documents, Brown Act compliance records (agendas 72-hr posting, closed session reports), franchise agreements, annexation/detachment resolutions, conflict-of-interest declarations, city charter amendments, emergency declarations, joint powers authori', 'B-14. City Council Member', 'City Council (general law or charter city). **Codes:** Gov. Code 34000-45343 (Govt of Cities); Cal. Const. Art. XI sec. 3-5. **Documents Audited:** City ordinances and resolutions, general plan adoption/amendments, budget documents, Brown Act compliance records (agendas 72-hr posting, closed session reports), franchise agreements, annexation/detachment resolutions, conflict-of-interest declarations, city charter amendments, emergency declarations, joint powers authority agreements.', '', 'City ordinances and resolutions, general plan adoption/amendments, budget documents, Brown Act compliance records (agendas 72-hr posting, closed session reports), franchise agreements, annexation/detachment resolutions, conflict-of-interest declarations, city charter amendments, emergency declarations, joint powers authority agreements.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00382', 'B-15. City Manager', 'California Local Unique Compliance', 'California Local Unique', 'B-15. City Manager — City Council (council-manager form). **Codes:** Gov. Code 34851-34861; city charter or municipal code. **Documents Audited:** Annual budget proposals, staff reports to council, contract execution documents (under delegation authority), department performance reports, emergency operations plans, ADA transition plans, labor memoranda of understanding (MOUs), organizational charts, annual financial reports (CAFR/ACFR), risk management reports, council policy implementation trac', 'B-15. City Manager', 'City Council (council-manager form). **Codes:** Gov. Code 34851-34861; city charter or municipal code. **Documents Audited:** Annual budget proposals, staff reports to council, contract execution documents (under delegation authority), department performance reports, emergency operations plans, ADA transition plans, labor memoranda of understanding (MOUs), organizational charts, annual financial reports (CAFR/ACFR), risk management reports, council policy implementation tracking.', '', 'Annual budget proposals, staff reports to council, contract execution documents (under delegation authority), department performance reports, emergency operations plans, ADA transition plans, labor memoranda of understanding (MOUs), organizational charts, annual financial reports (CAFR/ACFR), risk management reports, council policy implementation tracking.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00383', 'B-16. City Clerk', 'California Local Unique Compliance', 'California Local Unique', 'B-16. City Clerk — City Clerk''s Office. **Codes:** Gov. Code 36800-36840; Elec. Code 1301-1304, 10200-10264. **Documents Audited:** Ordinance and resolution files (codification), council meeting minutes, public records requests (CPRA compliance), FPPC filing officer duties (Form 700 repository), municipal election documents, conflict-of-interest code maintenance, records retention schedules, claims against city, bid opening records, oath of office filings, administrative citations, business lice', 'B-16. City Clerk', 'City Clerk''s Office. **Codes:** Gov. Code 36800-36840; Elec. Code 1301-1304, 10200-10264. **Documents Audited:** Ordinance and resolution files (codification), council meeting minutes, public records requests (CPRA compliance), FPPC filing officer duties (Form 700 repository), municipal election documents, conflict-of-interest code maintenance, records retention schedules, claims against city, bid opening records, oath of office filings, administrative citations, business license records.', '', 'Ordinance and resolution files (codification), council meeting minutes, public records requests (CPRA compliance), FPPC filing officer duties (Form 700 repository), municipal election documents, conflict-of-interest code maintenance, records retention schedules, claims against city, bid opening records, oath of office filings, administrative citations, business license records.');
