INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00385', 'B-18. City Planning Director', 'California Local Unique Compliance', 'California Local Unique', 'B-18. City Planning Director — City Planning/Zoning Department. **Codes:** Gov. Code 65000-66210 (Planning & Zoning Law); PRC 21000-21189.70 (CEQA); Gov. Code 65852.2 (ADU). **Documents Audited:** General plan elements (7 mandatory elements + optional), specific plans, zoning ordinance amendments, conditional use permits, variance applications, subdivision maps (tentative/final), environmental impact reports (EIRs), negative declarations/MNDs, housing element compliance (HCD review), density bon', 'B-18. City Planning Director', 'City Planning/Zoning Department. **Codes:** Gov. Code 65000-66210 (Planning & Zoning Law); PRC 21000-21189.70 (CEQA); Gov. Code 65852.2 (ADU). **Documents Audited:** General plan elements (7 mandatory elements + optional), specific plans, zoning ordinance amendments, conditional use permits, variance applications, subdivision maps (tentative/final), environmental impact reports (EIRs), negative declarations/MNDs, housing element compliance (HCD review), density bonus applications, ADU/JADU permi', '', 'General plan elements (7 mandatory elements + optional), specific plans, zoning ordinance amendments, conditional use permits, variance applications, subdivision maps (tentative/final), environmental impact reports (EIRs), negative declarations/MNDs, housing element compliance (HCD review), density bonus applications, ADU/JADU permits, SB 9 lot split applications, SB 10 urban infill resolutions, development agreements, Williamson Act contracts/non-renewal notices.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00386', 'B-19. Chief Building Official', 'California Local Unique Compliance', 'California Local Unique', 'B-19. Chief Building Official — City/County Building Department. **Codes:** HSC 17920-17928, 18900-18944 (State Housing Law); Cal. Building Code (CBC/Title 24); Gov. Code 65850-65863.13. **Documents Audited:** Building permit applications and approvals, plan check reports, inspection records (foundation through final), certificate of occupancy, Title 24 energy compliance (CF-1R/CF-2R), CalGreen compliance, ADA/accessibility compliance reports, unreinforced masonry building (URM) inventories, sei', 'B-19. Chief Building Official', 'City/County Building Department. **Codes:** HSC 17920-17928, 18900-18944 (State Housing Law); Cal. Building Code (CBC/Title 24); Gov. Code 65850-65863.13. **Documents Audited:** Building permit applications and approvals, plan check reports, inspection records (foundation through final), certificate of occupancy, Title 24 energy compliance (CF-1R/CF-2R), CalGreen compliance, ADA/accessibility compliance reports, unreinforced masonry building (URM) inventories, seismic retrofit compliance, solar ', '', 'Building permit applications and approvals, plan check reports, inspection records (foundation through final), certificate of occupancy, Title 24 energy compliance (CF-1R/CF-2R), CalGreen compliance, ADA/accessibility compliance reports, unreinforced masonry building (URM) inventories, seismic retrofit compliance, solar permit applications (AB 2188), SB 35 streamlined permits, code violation notices and abatement orders, demolition permits.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00387', 'B-20. Fire Chief', 'California Local Unique Compliance', 'California Local Unique', 'B-20. Fire Chief — City Fire Department or Fire Protection District. **Codes:** HSC 13000-13273 (State Fire Marshal); Cal. Fire Code (Title 24 Part 9); Gov. Code 51175-51189 (fire hazard zones). **Documents Audited:** Fire inspection reports, fire prevention plans, fire code violation notices, operational pre-fire plans, mutual/automatic aid agreements, fire investigation reports (arson), hazardous materials disclosure documents (HSC 25500-25520 CUPA), community risk assessments, fire sprinkler/', 'B-20. Fire Chief', 'City Fire Department or Fire Protection District. **Codes:** HSC 13000-13273 (State Fire Marshal); Cal. Fire Code (Title 24 Part 9); Gov. Code 51175-51189 (fire hazard zones). **Documents Audited:** Fire inspection reports, fire prevention plans, fire code violation notices, operational pre-fire plans, mutual/automatic aid agreements, fire investigation reports (arson), hazardous materials disclosure documents (HSC 25500-25520 CUPA), community risk assessments, fire sprinkler/alarm system plan c', '', 'Fire inspection reports, fire prevention plans, fire code violation notices, operational pre-fire plans, mutual/automatic aid agreements, fire investigation reports (arson), hazardous materials disclosure documents (HSC 25500-25520 CUPA), community risk assessments, fire sprinkler/alarm system plan checks, vegetation management plans (SRA/LRA), emergency response incident reports (NFIRS), firework permits, high-rise building inspection records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00388', 'B-21. Police Chief', 'California Local Unique Compliance', 'California Local Unique', 'B-21. Police Chief — City Police Department. **Codes:** Pen. Code 830.1, 832, 13519-13519.14 (POST standards); Gov. Code 3300-3313 (POBR). **Documents Audited:** Arrest reports, crime reports, use-of-force reports (AB 392/SB 230), body-worn camera footage logs, pursuit reports, internal affairs investigation files, civilian complaint disposition records, RIPA racial profiling data (Gov. Code 12525.5), towed vehicle reports, sex offender registration compliance, asset forfeiture records, communit', 'B-21. Police Chief', 'City Police Department. **Codes:** Pen. Code 830.1, 832, 13519-13519.14 (POST standards); Gov. Code 3300-3313 (POBR). **Documents Audited:** Arrest reports, crime reports, use-of-force reports (AB 392/SB 230), body-worn camera footage logs, pursuit reports, internal affairs investigation files, civilian complaint disposition records, RIPA racial profiling data (Gov. Code 12525.5), towed vehicle reports, sex offender registration compliance, asset forfeiture records, community policing plans, SB ', '', 'Arrest reports, crime reports, use-of-force reports (AB 392/SB 230), body-worn camera footage logs, pursuit reports, internal affairs investigation files, civilian complaint disposition records, RIPA racial profiling data (Gov. Code 12525.5), towed vehicle reports, sex offender registration compliance, asset forfeiture records, community policing plans, SB 1421/AB 748 disclosure records, Brady list maintenance, military equipment use reports (AB 481), surveillance technology policies.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00389', 'B-22. Director of Public Works', 'California Local Unique Compliance', 'California Local Unique', 'B-22. Director of Public Works — City/County Public Works Department. **Codes:** SHC 1-33700 (Streets & Highways); PCC 20100-22045 (public contracts); Gov. Code 4525-4529 (A&E services). **Documents Audited:** Capital improvement project plans, prevailing wage compliance records (Lab. Code 1770-1781), bid solicitation/award documents, encroachment permits, street/sidewalk/sewer improvement plans, stormwater management plans (MS4 permits), pavement management program reports, ADA curb ramp compli', 'B-22. Director of Public Works', 'City/County Public Works Department. **Codes:** SHC 1-33700 (Streets & Highways); PCC 20100-22045 (public contracts); Gov. Code 4525-4529 (A&E services). **Documents Audited:** Capital improvement project plans, prevailing wage compliance records (Lab. Code 1770-1781), bid solicitation/award documents, encroachment permits, street/sidewalk/sewer improvement plans, stormwater management plans (MS4 permits), pavement management program reports, ADA curb ramp compliance, traffic signal warrant anal', '', 'Capital improvement project plans, prevailing wage compliance records (Lab. Code 1770-1781), bid solicitation/award documents, encroachment permits, street/sidewalk/sewer improvement plans, stormwater management plans (MS4 permits), pavement management program reports, ADA curb ramp compliance, traffic signal warrant analyses, public contract change orders, notice of completion filings, retention payment releases, Prop 218 assessment ballots.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00390', 'B-23. Water District General Manager', 'California Local Unique Compliance', 'California Local Unique', 'B-23. Water District General Manager — Water District Board of Directors (formed under Wat. Code div. 12-20 or special act). **Codes:** Wat. Code 30000-38501 (county water districts), 34000-38501 (municipal water districts); HSC 116270-116755 (drinking water); Prop 218 (rates). **Documents Audited:** Water quality consumer confidence reports (CCR), source water assessments, water supply assessments (Gov. Code 66473.7), urban water management plans (Wat. Code 10610-10657), drought contingency pla', 'B-23. Water District General Manager', 'Water District Board of Directors (formed under Wat. Code div. 12-20 or special act). **Codes:** Wat. Code 30000-38501 (county water districts), 34000-38501 (municipal water districts); HSC 116270-116755 (drinking water); Prop 218 (rates). **Documents Audited:** Water quality consumer confidence reports (CCR), source water assessments, water supply assessments (Gov. Code 66473.7), urban water management plans (Wat. Code 10610-10657), drought contingency plans, water rate studies (Prop 218 compli', '', 'Water quality consumer confidence reports (CCR), source water assessments, water supply assessments (Gov. Code 66473.7), urban water management plans (Wat. Code 10610-10657), drought contingency plans, water rate studies (Prop 218 compliant), annual financial audits, SWRCB drinking water permits, distribution system monitoring, backflow prevention program records, lead and copper rule compliance, recycled water permits, water loss audits (SB 555).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00391', 'B-24. Fire Protection District Chief', 'California Local Unique Compliance', 'California Local Unique', 'B-24. Fire Protection District Chief — Fire Protection District Board (HSC 13800-13970). **Codes:** HSC 13800-13970 (fire protection districts); Gov. Code 50075-50077.5 (special taxes); Cal. Fire Code Title 24 Part 9. **Documents Audited:** District formation/annexation documents, special tax/assessment levy records, ISO rating documentation, apparatus and equipment inventories, volunteer firefighter certifications, station response time reports, community wildfire protection plans, development ', 'B-24. Fire Protection District Chief', 'Fire Protection District Board (HSC 13800-13970). **Codes:** HSC 13800-13970 (fire protection districts); Gov. Code 50075-50077.5 (special taxes); Cal. Fire Code Title 24 Part 9. **Documents Audited:** District formation/annexation documents, special tax/assessment levy records, ISO rating documentation, apparatus and equipment inventories, volunteer firefighter certifications, station response time reports, community wildfire protection plans, development impact fee justification studies, annua', '', 'District formation/annexation documents, special tax/assessment levy records, ISO rating documentation, apparatus and equipment inventories, volunteer firefighter certifications, station response time reports, community wildfire protection plans, development impact fee justification studies, annual independent financial audits, Prop 4/Gann limit calculations, mutual aid agreements.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00392', 'B-25. Sanitation District Engineer', 'California Local Unique Compliance', 'California Local Unique', 'B-25. Sanitation District Engineer — Sanitation/Sanitary District Board (HSC 6400-6830). **Codes:** HSC 5410-5476 (Porter-Cologne nexus), 6400-6830 (sanitary districts); Wat. Code 13000+; 40 CFR 122, 503 (federal NPDES). **Documents Audited:** NPDES permit compliance reports (DMRs), collection system monitoring reports, sanitary sewer management plans (SSMP), sanitary sewer overflow (SSO) reports, industrial pretreatment program records, biosolids management plans, capacity management plans, con', 'B-25. Sanitation District Engineer', 'Sanitation/Sanitary District Board (HSC 6400-6830). **Codes:** HSC 5410-5476 (Porter-Cologne nexus), 6400-6830 (sanitary districts); Wat. Code 13000+; 40 CFR 122, 503 (federal NPDES). **Documents Audited:** NPDES permit compliance reports (DMRs), collection system monitoring reports, sanitary sewer management plans (SSMP), sanitary sewer overflow (SSO) reports, industrial pretreatment program records, biosolids management plans, capacity management plans, connection fee studies, sewer system mas', '', 'NPDES permit compliance reports (DMRs), collection system monitoring reports, sanitary sewer management plans (SSMP), sanitary sewer overflow (SSO) reports, industrial pretreatment program records, biosolids management plans, capacity management plans, connection fee studies, sewer system master plans, CEQA documents for facility expansion.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00393', 'B-26. Parks and Recreation District Manager', 'California Local Unique Compliance', 'California Local Unique', 'B-26. Parks and Recreation District Manager — Recreation and Park District Board (PRC 5780-5791). **Codes:** PRC 5001-5076.3 (state parks nexus), 5780-5791 (park districts); Gov. Code 53090-53097.5 (exemptions). **Documents Audited:** District formation documents, park master plans, Prop 68/Prop 84 grant compliance, ADA accessibility audits for facilities, recreation programming records, user fee studies, lease agreements for district property, landscape and lighting assessment district records,', 'B-26. Parks and Recreation District Manager', 'Recreation and Park District Board (PRC 5780-5791). **Codes:** PRC 5001-5076.3 (state parks nexus), 5780-5791 (park districts); Gov. Code 53090-53097.5 (exemptions). **Documents Audited:** District formation documents, park master plans, Prop 68/Prop 84 grant compliance, ADA accessibility audits for facilities, recreation programming records, user fee studies, lease agreements for district property, landscape and lighting assessment district records, Quimby Act in-lieu fee calculations, environm', '', 'District formation documents, park master plans, Prop 68/Prop 84 grant compliance, ADA accessibility audits for facilities, recreation programming records, user fee studies, lease agreements for district property, landscape and lighting assessment district records, Quimby Act in-lieu fee calculations, environmental review for park improvements.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00394', 'B-27. Mosquito Abatement District Manager', 'California Local Unique Compliance', 'California Local Unique', 'B-27. Mosquito Abatement District Manager — Mosquito Abatement/Vector Control District Board (HSC 2000-2093). **Codes:** HSC 2000-2093 (mosquito abatement), 116110-116068 (vector control); FAC 12751-14102 (pesticide use). **Documents Audited:** Mosquito surveillance reports, pesticide use reports (DPR filings), best management practices plans, service request logs, annual budget and audit, CEQA compliance for treatment activities, integrated pest management (IPM) plans, public notification recor', 'B-27. Mosquito Abatement District Manager', 'Mosquito Abatement/Vector Control District Board (HSC 2000-2093). **Codes:** HSC 2000-2093 (mosquito abatement), 116110-116068 (vector control); FAC 12751-14102 (pesticide use). **Documents Audited:** Mosquito surveillance reports, pesticide use reports (DPR filings), best management practices plans, service request logs, annual budget and audit, CEQA compliance for treatment activities, integrated pest management (IPM) plans, public notification records for aerial/ground treatments, West Nile v', '', 'Mosquito surveillance reports, pesticide use reports (DPR filings), best management practices plans, service request logs, annual budget and audit, CEQA compliance for treatment activities, integrated pest management (IPM) plans, public notification records for aerial/ground treatments, West Nile virus monitoring data, special tax assessment records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00395', 'B-28. Cemetery District Manager', 'California Local Unique Compliance', 'California Local Unique', 'B-28. Cemetery District Manager — Cemetery District Board (HSC 8890-9068). **Codes:** HSC 7000-8030 (disposition of remains), 8890-9068 (cemetery districts); BPC 7600-7741 (Cemetery and Funeral Bureau). **Documents Audited:** Interment records, endowment care fund investment reports, plot sales contracts, annual financial audits, district formation/boundary documents, master plan for cemetery development, maintenance schedules, fee schedules, state controller''s special districts financial transa', 'B-28. Cemetery District Manager', 'Cemetery District Board (HSC 8890-9068). **Codes:** HSC 7000-8030 (disposition of remains), 8890-9068 (cemetery districts); BPC 7600-7741 (Cemetery and Funeral Bureau). **Documents Audited:** Interment records, endowment care fund investment reports, plot sales contracts, annual financial audits, district formation/boundary documents, master plan for cemetery development, maintenance schedules, fee schedules, state controller''s special districts financial transactions report, grave relocation or', '', 'Interment records, endowment care fund investment reports, plot sales contracts, annual financial audits, district formation/boundary documents, master plan for cemetery development, maintenance schedules, fee schedules, state controller''s special districts financial transactions report, grave relocation orders, environmental compliance for land expansion.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00396', 'B-29. Library District Director', 'California Local Unique Compliance', 'California Local Unique', 'B-29. Library District Director — Library District Board (Educ. Code 19400-19605). **Codes:** Educ. Code 18010-18203 (county free libraries), 19400-19605 (library districts); Gov. Code 6250-6270 (CPRA as it applies to library records). **Documents Audited:** Collection development policies, library services plans, patron privacy protection policies (Gov. Code 6267), annual statistics for State Library reporting, grant compliance (LSTA/CLSA), ADA accessibility plans, technology plans, intellectua', 'B-29. Library District Director', 'Library District Board (Educ. Code 19400-19605). **Codes:** Educ. Code 18010-18203 (county free libraries), 19400-19605 (library districts); Gov. Code 6250-6270 (CPRA as it applies to library records). **Documents Audited:** Collection development policies, library services plans, patron privacy protection policies (Gov. Code 6267), annual statistics for State Library reporting, grant compliance (LSTA/CLSA), ADA accessibility plans, technology plans, intellectual freedom policies, interlibrary l', '', 'Collection development policies, library services plans, patron privacy protection policies (Gov. Code 6267), annual statistics for State Library reporting, grant compliance (LSTA/CLSA), ADA accessibility plans, technology plans, intellectual freedom policies, interlibrary loan agreements, Friends of Library/foundation audit records, bond/measure expenditure reports.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00397', 'B-30. School District Superintendent', 'California Local Unique Compliance', 'California Local Unique', 'B-30. School District Superintendent — School District Board of Trustees. **Codes:** Educ. Code 35000-35179 (superintendent), 42100-42652 (school finance); Cal. Const. Art. IX. **Documents Audited:** Local Control Accountability Plan (LCAP), school accountability report cards (SARC), annual budget (adopted/interim), audit reports (Education Audits Appeal Panel standards), Williams settlement compliance (facilities, textbooks, teachers), collective bargaining agreements, special education local p', 'B-30. School District Superintendent', 'School District Board of Trustees. **Codes:** Educ. Code 35000-35179 (superintendent), 42100-42652 (school finance); Cal. Const. Art. IX. **Documents Audited:** Local Control Accountability Plan (LCAP), school accountability report cards (SARC), annual budget (adopted/interim), audit reports (Education Audits Appeal Panel standards), Williams settlement compliance (facilities, textbooks, teachers), collective bargaining agreements, special education local plan area (SELPA) compliance, student re', '', 'Local Control Accountability Plan (LCAP), school accountability report cards (SARC), annual budget (adopted/interim), audit reports (Education Audits Appeal Panel standards), Williams settlement compliance (facilities, textbooks, teachers), collective bargaining agreements, special education local plan area (SELPA) compliance, student records (FERPA/EdC 49060-49079), mandatory reporter training records, Title IX compliance files, school safety plans, facilities master plans, developer fee justification studies, Brown Act compliance for board meetings.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00398', 'B-31. Community College District Chancellor', 'California Local Unique Compliance', 'California Local Unique', 'B-31. Community College District Chancellor — Community College District Board of Trustees. **Codes:** Educ. Code 70900-87913 (community colleges); Cal. Code Regs. tit. 5 51000-59410; Cal. Const. Art. IX sec. 14. **Documents Audited:** Student Success Metrics reporting, accreditation self-evaluation reports (ACCJC), annual financial and compliance audits, FTES attendance accounting, 50% law instructional expenditure compliance (EdC 84362), equal employment opportunity plans, student equity plans', 'B-31. Community College District Chancellor', 'Community College District Board of Trustees. **Codes:** Educ. Code 70900-87913 (community colleges); Cal. Code Regs. tit. 5 51000-59410; Cal. Const. Art. IX sec. 14. **Documents Audited:** Student Success Metrics reporting, accreditation self-evaluation reports (ACCJC), annual financial and compliance audits, FTES attendance accounting, 50% law instructional expenditure compliance (EdC 84362), equal employment opportunity plans, student equity plans, faculty obligation numbers, curriculum appro', '', 'Student Success Metrics reporting, accreditation self-evaluation reports (ACCJC), annual financial and compliance audits, FTES attendance accounting, 50% law instructional expenditure compliance (EdC 84362), equal employment opportunity plans, student equity plans, faculty obligation numbers, curriculum approvals, Board of Governors fee waiver (California Promise/College Promise), facilities master plans, Prop 39 bond expenditure audits, Brown Act compliance.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00399', 'B-32. LAFCO Executive Officer', 'California Local Unique Compliance', 'California Local Unique', 'B-32. LAFCO Executive Officer — Local Agency Formation Commission (Gov. Code 56000-57550). **Codes:** Gov. Code 56000-57550 (Cortese-Knox-Hertzberg Act). **Documents Audited:** Municipal service reviews, sphere of influence determinations, annexation/detachment applications, incorporation/disincorporation studies, special district formation reviews, CEQA documents for boundary changes, protest proceedings, terms and conditions resolutions, out-of-area service agreements, island annexation analys', 'B-32. LAFCO Executive Officer', 'Local Agency Formation Commission (Gov. Code 56000-57550). **Codes:** Gov. Code 56000-57550 (Cortese-Knox-Hertzberg Act). **Documents Audited:** Municipal service reviews, sphere of influence determinations, annexation/detachment applications, incorporation/disincorporation studies, special district formation reviews, CEQA documents for boundary changes, protest proceedings, terms and conditions resolutions, out-of-area service agreements, island annexation analyses, disadvantaged unincorporated', '', 'Municipal service reviews, sphere of influence determinations, annexation/detachment applications, incorporation/disincorporation studies, special district formation reviews, CEQA documents for boundary changes, protest proceedings, terms and conditions resolutions, out-of-area service agreements, island annexation analyses, disadvantaged unincorporated community analyses, annual report of proposals.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00400', 'B-33. Grand Jury Foreperson', 'California Local Unique Compliance', 'California Local Unique', 'B-33. Grand Jury Foreperson — County Grand Jury. **Codes:** Pen. Code 888-939.91 (grand jury); Gov. Code 3060-3075 (accusation of officers). **Documents Audited:** Grand jury final reports (civil function), indictments (criminal function), county/city/special district operational review reports, responses from public agencies (90-day/150-day mandated responses per Pen. Code 933), complaint intake records, continuity reports, facility inspection reports (jails, juvenile halls per Pen. Code 919), ', 'B-33. Grand Jury Foreperson', 'County Grand Jury. **Codes:** Pen. Code 888-939.91 (grand jury); Gov. Code 3060-3075 (accusation of officers). **Documents Audited:** Grand jury final reports (civil function), indictments (criminal function), county/city/special district operational review reports, responses from public agencies (90-day/150-day mandated responses per Pen. Code 933), complaint intake records, continuity reports, facility inspection reports (jails, juvenile halls per Pen. Code 919), accusation proceedings against', '', 'Grand jury final reports (civil function), indictments (criminal function), county/city/special district operational review reports, responses from public agencies (90-day/150-day mandated responses per Pen. Code 933), complaint intake records, continuity reports, facility inspection reports (jails, juvenile halls per Pen. Code 919), accusation proceedings against public officers, audit findings of special districts.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00401', 'C-1. CEQA Compliance Specialist', 'California Local Unique Compliance', 'California Local Unique', 'C-1. CEQA Compliance Specialist — Lead agency (city/county/state) per Office of Planning and Research (OPR). **Codes:** PRC 21000-21189.70; Cal. Code Regs. tit. 14 15000-15387 (CEQA Guidelines); PRC 21091 (public review periods). **Documents Audited:** Initial studies, negative declarations, mitigated negative declarations, environmental impact reports (draft/final/supplemental), notices of preparation/determination/completion/exemption, mitigation monitoring and reporting programs, findings of ', 'C-1. CEQA Compliance Specialist', 'Lead agency (city/county/state) per Office of Planning and Research (OPR). **Codes:** PRC 21000-21189.70; Cal. Code Regs. tit. 14 15000-15387 (CEQA Guidelines); PRC 21091 (public review periods). **Documents Audited:** Initial studies, negative declarations, mitigated negative declarations, environmental impact reports (draft/final/supplemental), notices of preparation/determination/completion/exemption, mitigation monitoring and reporting programs, findings of overriding consideration, statemen', '', 'Initial studies, negative declarations, mitigated negative declarations, environmental impact reports (draft/final/supplemental), notices of preparation/determination/completion/exemption, mitigation monitoring and reporting programs, findings of overriding consideration, statement of overriding considerations, EIR certification records, CEQA exemption determinations (categorical/statutory/common sense), AB 52 tribal consultation records, SB 18 tribal consultation records, Sustainable Communities Environmental Assessment (SCEA) documents.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00402', 'C-2. Proposition 65 Compliance Officer', 'California Local Unique Compliance', 'California Local Unique', 'C-2. Proposition 65 Compliance Officer — Office of Environmental Health Hazard Assessment (OEHHA). **Codes:** HSC 25249.5-25249.14 (Safe Drinking Water and Toxic Enforcement Act of 1986). **Documents Audited:** Prop 65 warning labels and signage, clear and reasonable warning assessments, 60-day notice of violation letters, safe harbor warning compliance documents, chemical exposure assessment reports, Prop 65 settlement agreements, annual reporter discharge reports, product testing and reformula', 'C-2. Proposition 65 Compliance Officer', 'Office of Environmental Health Hazard Assessment (OEHHA). **Codes:** HSC 25249.5-25249.14 (Safe Drinking Water and Toxic Enforcement Act of 1986). **Documents Audited:** Prop 65 warning labels and signage, clear and reasonable warning assessments, 60-day notice of violation letters, safe harbor warning compliance documents, chemical exposure assessment reports, Prop 65 settlement agreements, annual reporter discharge reports, product testing and reformulation records, short-form/long-form warnin', '', 'Prop 65 warning labels and signage, clear and reasonable warning assessments, 60-day notice of violation letters, safe harbor warning compliance documents, chemical exposure assessment reports, Prop 65 settlement agreements, annual reporter discharge reports, product testing and reformulation records, short-form/long-form warning evaluations, OEHHA listed chemical applicability analyses.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00403', 'C-3. CCPA/CPRA Privacy Compliance Officer', 'California Local Unique Compliance', 'California Local Unique', 'C-3. CCPA/CPRA Privacy Compliance Officer — California Privacy Protection Agency (CPPA). **Codes:** Civ. Code 1798.100-1798.199.100 (CCPA/CPRA); Cal. Code Regs. tit. 11 7000-7102. **Documents Audited:** Privacy policies (website and offline), consumer rights request logs (access/delete/correct/opt-out), data processing agreements, data protection impact assessments, service provider/contractor agreements, opt-out preference signal compliance, financial incentive notices, privacy impact assessmen', 'C-3. CCPA/CPRA Privacy Compliance Officer', 'California Privacy Protection Agency (CPPA). **Codes:** Civ. Code 1798.100-1798.199.100 (CCPA/CPRA); Cal. Code Regs. tit. 11 7000-7102. **Documents Audited:** Privacy policies (website and offline), consumer rights request logs (access/delete/correct/opt-out), data processing agreements, data protection impact assessments, service provider/contractor agreements, opt-out preference signal compliance, financial incentive notices, privacy impact assessments for high-risk processing, data broker reg', '', 'Privacy policies (website and offline), consumer rights request logs (access/delete/correct/opt-out), data processing agreements, data protection impact assessments, service provider/contractor agreements, opt-out preference signal compliance, financial incentive notices, privacy impact assessments for high-risk processing, data broker registrations, annual cybersecurity audit reports (for high-risk businesses), risk assessment submissions to CPPA, employee/HR privacy notices, children''s data (under-16 opt-in consent records).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00404', 'C-4. SB 1383 Organic Waste Compliance Monitor', 'California Local Unique Compliance', 'California Local Unique', 'C-4. SB 1383 Organic Waste Compliance Monitor — CalRecycle. **Codes:** PRC 42652.5-42654; Cal. Code Regs. tit. 14 18981-18998 (SB 1383 Short-Lived Climate Pollutants). **Documents Audited:** Jurisdiction implementation records (ordinance, outreach), organic waste collection service records, edible food recovery agreements, contamination monitoring reports, waivers granted (de minimis, physical space), annual compliance reports to CalRecycle, procurement records (recycled organic waste products/r', 'C-4. SB 1383 Organic Waste Compliance Monitor', 'CalRecycle. **Codes:** PRC 42652.5-42654; Cal. Code Regs. tit. 14 18981-18998 (SB 1383 Short-Lived Climate Pollutants). **Documents Audited:** Jurisdiction implementation records (ordinance, outreach), organic waste collection service records, edible food recovery agreements, contamination monitoring reports, waivers granted (de minimis, physical space), annual compliance reports to CalRecycle, procurement records (recycled organic waste products/renewable gas), enforcement action records, route', '', 'Jurisdiction implementation records (ordinance, outreach), organic waste collection service records, edible food recovery agreements, contamination monitoring reports, waivers granted (de minimis, physical space), annual compliance reports to CalRecycle, procurement records (recycled organic waste products/renewable gas), enforcement action records, route review documentation, self-hauler compliance, capacity planning analyses.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00405', 'C-5. AB 5/ABC Test Worker Classification Auditor', 'California Local Unique Compliance', 'California Local Unique', 'C-5. AB 5/ABC Test Worker Classification Auditor — EDD / Labor Commissioner / Attorney General. **Codes:** Lab. Code 2775-2787 (AB 5/AB 2257); UIC 621(b), 606.5 (ABC test); Dynamex Operations West v. Superior Court (2018). **Documents Audited:** Worker classification analyses (A-B-C prong evaluations), independent contractor agreements, EDD employment determination rulings (DE 1870), payroll records, 1099 vs. W-2 classifications, Borello factor analyses for exempt categories, business-to-busines', 'C-5. AB 5/ABC Test Worker Classification Auditor', 'EDD / Labor Commissioner / Attorney General. **Codes:** Lab. Code 2775-2787 (AB 5/AB 2257); UIC 621(b), 606.5 (ABC test); Dynamex Operations West v. Superior Court (2018). **Documents Audited:** Worker classification analyses (A-B-C prong evaluations), independent contractor agreements, EDD employment determination rulings (DE 1870), payroll records, 1099 vs. W-2 classifications, Borello factor analyses for exempt categories, business-to-business exemption documentation, referral agency exemptio', '', 'Worker classification analyses (A-B-C prong evaluations), independent contractor agreements, EDD employment determination rulings (DE 1870), payroll records, 1099 vs. W-2 classifications, Borello factor analyses for exempt categories, business-to-business exemption documentation, referral agency exemptions, professional services exemption records, industry-specific exemption compliance (trucking, musicians, freelance writers, etc.).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00406', 'C-6. PAGA Claims Administrator', 'California Local Unique Compliance', 'California Local Unique', 'C-6. PAGA Claims Administrator — Labor & Workforce Development Agency (LWDA). **Codes:** Lab. Code 2698-2699.8 (Private Attorneys General Act); Lab. Code 200-243, 510-558 (underlying wage/hour). **Documents Audited:** PAGA notice letters to LWDA (online portal), LWDA response/non-response records, representative action complaint filings, settlement approval documents, penalty allocation records (75% LWDA/25% employees), cure provisions (Lab. Code 2699.3), manageability analyses, claim administra', 'C-6. PAGA Claims Administrator', 'Labor & Workforce Development Agency (LWDA). **Codes:** Lab. Code 2698-2699.8 (Private Attorneys General Act); Lab. Code 200-243, 510-558 (underlying wage/hour). **Documents Audited:** PAGA notice letters to LWDA (online portal), LWDA response/non-response records, representative action complaint filings, settlement approval documents, penalty allocation records (75% LWDA/25% employees), cure provisions (Lab. Code 2699.3), manageability analyses, claim administration and distribution records, em', '', 'PAGA notice letters to LWDA (online portal), LWDA response/non-response records, representative action complaint filings, settlement approval documents, penalty allocation records (75% LWDA/25% employees), cure provisions (Lab. Code 2699.3), manageability analyses, claim administration and distribution records, employer Labor Code violation documentation, PAGA waiver validity assessments.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00407', 'C-7. Unruh Civil Rights Act Compliance Analyst', 'California Local Unique Compliance', 'California Local Unique', 'C-7. Unruh Civil Rights Act Compliance Analyst — California Civil Rights Department (CRD, formerly DFEH). **Codes:** Civ. Code 51-53 (Unruh Act); Civ. Code 51.7 (Ralph Act — violence/threats); Civ. Code 52.1 (Bane Act — interference with rights). **Documents Audited:** Discrimination complaint files, public accommodation access audit reports, ADA nexus analyses (Unruh incorporates ADA), business anti-discrimination policies, Ralph Act hate violence reports, Bane Act interference-by-threat invest', 'C-7. Unruh Civil Rights Act Compliance Analyst', 'California Civil Rights Department (CRD, formerly DFEH). **Codes:** Civ. Code 51-53 (Unruh Act); Civ. Code 51.7 (Ralph Act — violence/threats); Civ. Code 52.1 (Bane Act — interference with rights). **Documents Audited:** Discrimination complaint files, public accommodation access audit reports, ADA nexus analyses (Unruh incorporates ADA), business anti-discrimination policies, Ralph Act hate violence reports, Bane Act interference-by-threat investigations, damages and injunctive relief records, ', '', 'Discrimination complaint files, public accommodation access audit reports, ADA nexus analyses (Unruh incorporates ADA), business anti-discrimination policies, Ralph Act hate violence reports, Bane Act interference-by-threat investigations, damages and injunctive relief records, website/digital accessibility assessments (Unruh extension to online), construction-related accessibility standards (CASP inspections), pre-litigation demand letters (CIV 55.3).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00408', 'C-8. Rosenthal Fair Debt Collection Practices Act Auditor', 'California Local Unique Compliance', 'California Local Unique', 'C-8. Rosenthal Fair Debt Collection Practices Act Auditor — Department of Financial Protection and Innovation (DFPI). **Codes:** Civ. Code 1788-1788.33 (Rosenthal Act); 15 USC 1692 (FDCPA, incorporated by reference). **Documents Audited:** Debt collection communications (letters, calls, texts), validation of debt notices, cease-and-desist compliance records, debtor dispute files, creditor assignment documentation, time-barred debt disclosures, credit reporting dispute records, original creditor ', 'C-8. Rosenthal Fair Debt Collection Practices Act Auditor', 'Department of Financial Protection and Innovation (DFPI). **Codes:** Civ. Code 1788-1788.33 (Rosenthal Act); 15 USC 1692 (FDCPA, incorporated by reference). **Documents Audited:** Debt collection communications (letters, calls, texts), validation of debt notices, cease-and-desist compliance records, debtor dispute files, creditor assignment documentation, time-barred debt disclosures, credit reporting dispute records, original creditor collection practices, collection agency licensing records, s', '', 'Debt collection communications (letters, calls, texts), validation of debt notices, cease-and-desist compliance records, debtor dispute files, creditor assignment documentation, time-barred debt disclosures, credit reporting dispute records, original creditor collection practices, collection agency licensing records, statutory damages and attorney fee exposure analyses, medical debt collection compliance (AB 1020).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00409', 'C-9. Song-Beverly Consumer Warranty Act Analyst (Lemon Law)', 'California Local Unique Compliance', 'California Local Unique', 'C-9. Song-Beverly Consumer Warranty Act Analyst (Lemon Law) — Department of Consumer Affairs / courts. **Codes:** Civ. Code 1790-1795.8 (Song-Beverly); Civ. Code 1793.2(d) (replacement/refund). **Documents Audited:** New vehicle warranty repair histories, manufacturer repair attempt records, consumer notification of rights documents, buyback/replacement offer letters, civil penalty (willful violation) assessments, manufacturer warranty policies, dealer repair orders, service bulletins (TSBs), ar', 'C-9. Song-Beverly Consumer Warranty Act Analyst (Lemon Law)', 'Department of Consumer Affairs / courts. **Codes:** Civ. Code 1790-1795.8 (Song-Beverly); Civ. Code 1793.2(d) (replacement/refund). **Documents Audited:** New vehicle warranty repair histories, manufacturer repair attempt records, consumer notification of rights documents, buyback/replacement offer letters, civil penalty (willful violation) assessments, manufacturer warranty policies, dealer repair orders, service bulletins (TSBs), arbitration program certifications (DCA-certified), used vehicle', '', 'New vehicle warranty repair histories, manufacturer repair attempt records, consumer notification of rights documents, buyback/replacement offer letters, civil penalty (willful violation) assessments, manufacturer warranty policies, dealer repair orders, service bulletins (TSBs), arbitration program certifications (DCA-certified), used vehicle implied warranty documentation (Civ. Code 1795.5), restitution calculations (mileage offset, incidental damages).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00410', 'C-10. FEHA Employment Discrimination Investigator', 'California Local Unique Compliance', 'California Local Unique', 'C-10. FEHA Employment Discrimination Investigator — California Civil Rights Department (CRD). **Codes:** Gov. Code 12900-12996 (Fair Employment and Housing Act); Cal. Code Regs. tit. 2 11000-11141. **Documents Audited:** CRD administrative complaints and right-to-sue notices, employer anti-harassment/anti-discrimination policies, reasonable accommodation interactive process records, investigation files (witness statements, documentary evidence), mediation/conciliation records, annual employer FE', 'C-10. FEHA Employment Discrimination Investigator', 'California Civil Rights Department (CRD). **Codes:** Gov. Code 12900-12996 (Fair Employment and Housing Act); Cal. Code Regs. tit. 2 11000-11141. **Documents Audited:** CRD administrative complaints and right-to-sue notices, employer anti-harassment/anti-discrimination policies, reasonable accommodation interactive process records, investigation files (witness statements, documentary evidence), mediation/conciliation records, annual employer FEHA training records (SB 1343 — 2-hour supervisory, 1', '', 'CRD administrative complaints and right-to-sue notices, employer anti-harassment/anti-discrimination policies, reasonable accommodation interactive process records, investigation files (witness statements, documentary evidence), mediation/conciliation records, annual employer FEHA training records (SB 1343 — 2-hour supervisory, 1-hour non-supervisory), DFEH-185 complaints, pregnancy disability leave documentation, religious accommodation requests, transgender rights compliance records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00411', 'C-11. CFRA Leave Administrator', 'California Local Unique Compliance', 'California Local Unique', 'C-11. CFRA Leave Administrator — CRD (enforcement); employer HR departments. **Codes:** Gov. Code 12945.1-12945.2 (California Family Rights Act); Cal. Code Regs. tit. 2 11087-11097. **Documents Audited:** CFRA leave request forms, medical certification documents, employer designation notices, fitness-for-duty certifications, intermittent leave tracking records, key employee exemption analyses, CFRA/FMLA concurrent leave tracking, new parent leave documentation (5-19 employee threshold), reinstat', 'C-11. CFRA Leave Administrator', 'CRD (enforcement); employer HR departments. **Codes:** Gov. Code 12945.1-12945.2 (California Family Rights Act); Cal. Code Regs. tit. 2 11087-11097. **Documents Audited:** CFRA leave request forms, medical certification documents, employer designation notices, fitness-for-duty certifications, intermittent leave tracking records, key employee exemption analyses, CFRA/FMLA concurrent leave tracking, new parent leave documentation (5-19 employee threshold), reinstatement records, retaliation compla', '', 'CFRA leave request forms, medical certification documents, employer designation notices, fitness-for-duty certifications, intermittent leave tracking records, key employee exemption analyses, CFRA/FMLA concurrent leave tracking, new parent leave documentation (5-19 employee threshold), reinstatement records, retaliation complaint files, leave balance and exhaustion records, military exigency/caregiver leave records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00412', 'C-12. California WARN Act Compliance Officer', 'California Local Unique Compliance', 'California Local Unique', 'C-12. California WARN Act Compliance Officer — EDD (notice recipient). **Codes:** Lab. Code 1400-1408 (Cal-WARN); 29 USC 2101-2109 (federal WARN for comparison). **Documents Audited:** 60-day advance notice of mass layoff/plant closing/relocation, notice to EDD/LWDA/local chief elected official, employee notification letters, relocation determinations (100+ miles), conditional notice documents, faltering company defense records, unforeseeable business circumstance documentation, natural disaster', 'C-12. California WARN Act Compliance Officer', 'EDD (notice recipient). **Codes:** Lab. Code 1400-1408 (Cal-WARN); 29 USC 2101-2109 (federal WARN for comparison). **Documents Audited:** 60-day advance notice of mass layoff/plant closing/relocation, notice to EDD/LWDA/local chief elected official, employee notification letters, relocation determinations (100+ miles), conditional notice documents, faltering company defense records, unforeseeable business circumstance documentation, natural disaster exemption filings, back pay and benefit calcul', '', '60-day advance notice of mass layoff/plant closing/relocation, notice to EDD/LWDA/local chief elected official, employee notification letters, relocation determinations (100+ miles), conditional notice documents, faltering company defense records, unforeseeable business circumstance documentation, natural disaster exemption filings, back pay and benefit calculations for violations, WARN exception analyses (temporary facilities, strikes/lockouts).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00413', 'C-13. Marsy''s Law Victim Rights Compliance Officer', 'California Local Unique Compliance', 'California Local Unique', 'C-13. Marsy''s Law Victim Rights Compliance Officer — County DA/courts/law enforcement. **Codes:** Cal. Const. Art. I sec. 28 (Prop 9/Marsy''s Law); Pen. Code 679-680.4, 1191.1-1191.25, 3043-3043.25. **Documents Audited:** Victim notification records (arrest, charges, hearings, release), restitution orders and collection records, victim impact statements, parole hearing notification compliance, protective order issuance records, VINE (Victim Information and Notification Everyday) registration logs', 'C-13. Marsy''s Law Victim Rights Compliance Officer', 'County DA/courts/law enforcement. **Codes:** Cal. Const. Art. I sec. 28 (Prop 9/Marsy''s Law); Pen. Code 679-680.4, 1191.1-1191.25, 3043-3043.25. **Documents Audited:** Victim notification records (arrest, charges, hearings, release), restitution orders and collection records, victim impact statements, parole hearing notification compliance, protective order issuance records, VINE (Victim Information and Notification Everyday) registration logs, victim privacy protection records, return of proper', '', 'Victim notification records (arrest, charges, hearings, release), restitution orders and collection records, victim impact statements, parole hearing notification compliance, protective order issuance records, VINE (Victim Information and Notification Everyday) registration logs, victim privacy protection records, return of property documentation, right to be heard at sentencing records, custody status change notifications.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00414', 'C-14. Three Strikes/Prop 36/Prop 47/Prop 57 Sentencing Analyst', 'California Local Unique Compliance', 'California Local Unique', 'C-14. Three Strikes/Prop 36/Prop 47/Prop 57 Sentencing Analyst — Courts / CDCR / County DA / Public Defender. **Codes:** Pen. Code 667(b)-(i), 1170.12 (Three Strikes); Pen. Code 1170.126 (Prop 36 resentencing); Pen. Code 1170.18 (Prop 47 reclassification); Cal. Const. Art. I sec. 32 (Prop 57 parole). **Documents Audited:** Strike prior allegations and proof, petition for resentencing under Prop 36 (third strike non-violent), Prop 47 reclassification/redesignation petitions, Prop 57 early parole ', 'C-14. Three Strikes/Prop 36/Prop 47/Prop 57 Sentencing Analyst', 'Courts / CDCR / County DA / Public Defender. **Codes:** Pen. Code 667(b)-(i), 1170.12 (Three Strikes); Pen. Code 1170.126 (Prop 36 resentencing); Pen. Code 1170.18 (Prop 47 reclassification); Cal. Const. Art. I sec. 32 (Prop 57 parole). **Documents Audited:** Strike prior allegations and proof, petition for resentencing under Prop 36 (third strike non-violent), Prop 47 reclassification/redesignation petitions, Prop 57 early parole consideration documents, CDCR credit-earning calculations, danger', '', 'Strike prior allegations and proof, petition for resentencing under Prop 36 (third strike non-violent), Prop 47 reclassification/redesignation petitions, Prop 57 early parole consideration documents, CDCR credit-earning calculations, dangerousness assessments, criminal history verification (RAP sheets), victim opposition/support statements, district attorney responses to petitions, court orders granting/denying relief.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00415', 'C-15. SB 9/SB 10 Housing Compliance Planner', 'California Local Unique Compliance', 'California Local Unique', 'C-15. SB 9/SB 10 Housing Compliance Planner — City/County Planning Department; HCD (oversight). **Codes:** Gov. Code 65852.21 (SB 9 lot splits/duplexes), 65913.5 (SB 10 up-to-10-unit zoning); Gov. Code 65589.5 (Housing Accountability Act). **Documents Audited:** SB 9 ministerial lot split applications, SB 9 duplex permit applications, owner-occupancy affidavits (3-year requirement), SB 10 zoning resolutions, objective design standard compliance, demolition history reviews (no Ellis Act eviction ', 'C-15. SB 9/SB 10 Housing Compliance Planner', 'City/County Planning Department; HCD (oversight). **Codes:** Gov. Code 65852.21 (SB 9 lot splits/duplexes), 65913.5 (SB 10 up-to-10-unit zoning); Gov. Code 65589.5 (Housing Accountability Act). **Documents Audited:** SB 9 ministerial lot split applications, SB 9 duplex permit applications, owner-occupancy affidavits (3-year requirement), SB 10 zoning resolutions, objective design standard compliance, demolition history reviews (no Ellis Act eviction within prior 15 years), historic district exem', '', 'SB 9 ministerial lot split applications, SB 9 duplex permit applications, owner-occupancy affidavits (3-year requirement), SB 10 zoning resolutions, objective design standard compliance, demolition history reviews (no Ellis Act eviction within prior 15 years), historic district exemption analyses, Housing Accountability Act denial justifications, density bonus application reviews (Gov. Code 65915), streamlined ministerial approval records (SB 35).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00416', 'C-16. Costa-Hawkins/Rent Stabilization Compliance Analyst', 'California Local Unique Compliance', 'California Local Unique', 'C-16. Costa-Hawkins/Rent Stabilization Compliance Analyst — City rent boards (SF, LA, Oakland, Berkeley, etc.). **Codes:** Civ. Code 1947.12-1947.13 (AB 1482/Tenant Protection Act); Civ. Code 1954.50-1954.535 (Costa-Hawkins); local rent stabilization ordinances. **Documents Audited:** Rent increase notices and calculations (CPI-based caps), just cause eviction documentation, Costa-Hawkins vacancy decontrol records, AB 1482 exemption determinations (single-family/15-year-new construction), tenant', 'C-16. Costa-Hawkins/Rent Stabilization Compliance Analyst', 'City rent boards (SF, LA, Oakland, Berkeley, etc.). **Codes:** Civ. Code 1947.12-1947.13 (AB 1482/Tenant Protection Act); Civ. Code 1954.50-1954.535 (Costa-Hawkins); local rent stabilization ordinances. **Documents Audited:** Rent increase notices and calculations (CPI-based caps), just cause eviction documentation, Costa-Hawkins vacancy decontrol records, AB 1482 exemption determinations (single-family/15-year-new construction), tenant habitability complaint files, relocation assistance calcula', '', 'Rent increase notices and calculations (CPI-based caps), just cause eviction documentation, Costa-Hawkins vacancy decontrol records, AB 1482 exemption determinations (single-family/15-year-new construction), tenant habitability complaint files, relocation assistance calculations, owner move-in eviction compliance, capital improvement passthrough petitions, rent board annual registration filings, Ellis Act withdrawal notices (Gov. Code 7060-7060.7).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00417', 'C-17. Ellis Act Compliance Specialist', 'California Local Unique Compliance', 'California Local Unique', 'C-17. Ellis Act Compliance Specialist — City/County (enforcement); courts. **Codes:** Gov. Code 7060-7060.7 (Ellis Act). **Documents Audited:** Notice of intent to withdraw rental units, 120-day/1-year tenant notification records, elderly/disabled tenant extended notice compliance (1 year), relocation assistance payment records, recorded memorandum of withdrawal, re-rental restriction compliance (5-year/10-year), city notification filings, rescission of withdrawal documents, tenant right of firs', 'C-17. Ellis Act Compliance Specialist', 'City/County (enforcement); courts. **Codes:** Gov. Code 7060-7060.7 (Ellis Act). **Documents Audited:** Notice of intent to withdraw rental units, 120-day/1-year tenant notification records, elderly/disabled tenant extended notice compliance (1 year), relocation assistance payment records, recorded memorandum of withdrawal, re-rental restriction compliance (5-year/10-year), city notification filings, rescission of withdrawal documents, tenant right of first refusal records.', '', 'Notice of intent to withdraw rental units, 120-day/1-year tenant notification records, elderly/disabled tenant extended notice compliance (1 year), relocation assistance payment records, recorded memorandum of withdrawal, re-rental restriction compliance (5-year/10-year), city notification filings, rescission of withdrawal documents, tenant right of first refusal records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00418', 'C-18. Williamson Act Administrator', 'California Local Unique Compliance', 'California Local Unique', 'C-18. Williamson Act Administrator — County (with Dept. of Conservation oversight). **Codes:** Gov. Code 51200-51297.4 (California Land Conservation Act/Williamson Act); RTC 421-423 (assessment). **Documents Audited:** Agricultural preserve establishment documents, land conservation (Williamson Act) contracts, non-renewal filings and 9-year phase-out calculations, cancellation petitions and findings of inconsistency, Farmland Security Zone contracts (super Williamson), compatible use determinati', 'C-18. Williamson Act Administrator', 'County (with Dept. of Conservation oversight). **Codes:** Gov. Code 51200-51297.4 (California Land Conservation Act/Williamson Act); RTC 421-423 (assessment). **Documents Audited:** Agricultural preserve establishment documents, land conservation (Williamson Act) contracts, non-renewal filings and 9-year phase-out calculations, cancellation petitions and findings of inconsistency, Farmland Security Zone contracts (super Williamson), compatible use determinations, assessor restricted value calcul', '', 'Agricultural preserve establishment documents, land conservation (Williamson Act) contracts, non-renewal filings and 9-year phase-out calculations, cancellation petitions and findings of inconsistency, Farmland Security Zone contracts (super Williamson), compatible use determinations, assessor restricted value calculations, subvention payment claims to state, Dept. of Conservation biennial reports.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00419', 'C-19. Brown Act Compliance Advisor', 'California Local Unique Compliance', 'California Local Unique', 'C-19. Brown Act Compliance Advisor — County DA (enforcement); Attorney General; courts. **Codes:** Gov. Code 54950-54963 (Ralph M. Brown Act). **Documents Audited:** Regular/special meeting agendas (72-hour/24-hour posting), closed session agenda descriptions, public comment procedures, meeting minutes/recordings, teleconference compliance (AB 2449), serial meeting prohibition compliance, action taken in closed session reports, cure/correct demands and responses, Brown Act violation complaint fi', 'C-19. Brown Act Compliance Advisor', 'County DA (enforcement); Attorney General; courts. **Codes:** Gov. Code 54950-54963 (Ralph M. Brown Act). **Documents Audited:** Regular/special meeting agendas (72-hour/24-hour posting), closed session agenda descriptions, public comment procedures, meeting minutes/recordings, teleconference compliance (AB 2449), serial meeting prohibition compliance, action taken in closed session reports, cure/correct demands and responses, Brown Act violation complaint files, legislative body bylaws, standin', '', 'Regular/special meeting agendas (72-hour/24-hour posting), closed session agenda descriptions, public comment procedures, meeting minutes/recordings, teleconference compliance (AB 2449), serial meeting prohibition compliance, action taken in closed session reports, cure/correct demands and responses, Brown Act violation complaint files, legislative body bylaws, standing committee compliance, accessibility of meeting materials.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00420', 'C-20. California Public Records Act (CPRA) Compliance Officer', 'California Local Unique Compliance', 'California Local Unique', 'C-20. California Public Records Act (CPRA) Compliance Officer — Public agency (responding); courts (enforcement). **Codes:** Gov. Code 6250-6270 (CPRA); Gov. Code 7920.000-7931.000 (recodified CPRA effective 2023). **Documents Audited:** Public records requests and response logs, 10-day determination records, exemption justification memoranda, redaction logs with cited exemptions, fee calculations (direct cost of duplication), electronic records format compliance, Vaughn index preparation, litig', 'C-20. California Public Records Act (CPRA) Compliance Officer', 'Public agency (responding); courts (enforcement). **Codes:** Gov. Code 6250-6270 (CPRA); Gov. Code 7920.000-7931.000 (recodified CPRA effective 2023). **Documents Audited:** Public records requests and response logs, 10-day determination records, exemption justification memoranda, redaction logs with cited exemptions, fee calculations (direct cost of duplication), electronic records format compliance, Vaughn index preparation, litigation privilege logs, proactive disclosure (Gov. Code 6253.10), ', '', 'Public records requests and response logs, 10-day determination records, exemption justification memoranda, redaction logs with cited exemptions, fee calculations (direct cost of duplication), electronic records format compliance, Vaughn index preparation, litigation privilege logs, proactive disclosure (Gov. Code 6253.10), records retention schedules, elected official communications (text/email subject to CPRA).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00421', 'C-21. Political Reform Act Compliance Advisor', 'California Local Unique Compliance', 'California Local Unique', 'C-21. Political Reform Act Compliance Advisor — FPPC (primary); local agencies. **Codes:** Gov. Code 81000-91015 (Political Reform Act); Cal. Code Regs. tit. 2 18110-18997. **Documents Audited:** Conflict-of-interest codes (biennial review), Form 700 filing compliance, campaign contribution limits, mass mailing restrictions, government-funded campaign activity prohibitions, gift limit compliance ($590 in 2025-26), revolving door restrictions, behested payment reports, ballot measure advocacy res', 'C-21. Political Reform Act Compliance Advisor', 'FPPC (primary); local agencies. **Codes:** Gov. Code 81000-91015 (Political Reform Act); Cal. Code Regs. tit. 2 18110-18997. **Documents Audited:** Conflict-of-interest codes (biennial review), Form 700 filing compliance, campaign contribution limits, mass mailing restrictions, government-funded campaign activity prohibitions, gift limit compliance ($590 in 2025-26), revolving door restrictions, behested payment reports, ballot measure advocacy restrictions, misuse of public position analyses, S', '', 'Conflict-of-interest codes (biennial review), Form 700 filing compliance, campaign contribution limits, mass mailing restrictions, government-funded campaign activity prohibitions, gift limit compliance ($590 in 2025-26), revolving door restrictions, behested payment reports, ballot measure advocacy restrictions, misuse of public position analyses, Section 1090 conflict (Gov. Code 1090-1099) reviews, incompatible office determinations.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00422', 'C-22. Knox-Keene Health Plan Compliance Officer', 'California Local Unique Compliance', 'California Local Unique', 'C-22. Knox-Keene Health Plan Compliance Officer — Department of Managed Health Care (DMHC). **Codes:** HSC 1340-1399.907 (Knox-Keene Health Care Service Plan Act); Cal. Code Regs. tit. 28. **Documents Audited:** Health plan license applications and renewals, provider network adequacy reports (timely access standards), grievance and appeal records, independent medical review (IMR) files, financial solvency reports (tangible net equity), quality assurance/HEDIS reports, utilization management poli', 'C-22. Knox-Keene Health Plan Compliance Officer', 'Department of Managed Health Care (DMHC). **Codes:** HSC 1340-1399.907 (Knox-Keene Health Care Service Plan Act); Cal. Code Regs. tit. 28. **Documents Audited:** Health plan license applications and renewals, provider network adequacy reports (timely access standards), grievance and appeal records, independent medical review (IMR) files, financial solvency reports (tangible net equity), quality assurance/HEDIS reports, utilization management policies, mental health parity compliance, SB 17 drug ', '', 'Health plan license applications and renewals, provider network adequacy reports (timely access standards), grievance and appeal records, independent medical review (IMR) files, financial solvency reports (tangible net equity), quality assurance/HEDIS reports, utilization management policies, mental health parity compliance, SB 17 drug price transparency reports, surprise billing compliance (AB 72), premium rate filings (large group), annual compliance plan submissions, cultural and linguistic services assessments.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00423', 'Persona: ABC-ENFORCEMENT-AUDITOR', 'California State Depts Compliance', 'California State Depts', 'Persona: ABC-ENFORCEMENT-AUDITOR — Attorney General (elected constitutional officer); Cal. Const. Art. V, sec. 13; Key Statute:** Gov. Code 12500-12599.7; Penal Code various; BPC various (charitable trusts: Gov. Code 12580-12599.7); Document Types:** AG opinions, CLETS records, DOJ firearms records (DROS/AFS), charitable trust filings (CT-1/CT-2/RRF-1), Megan''s Law registrations, crime statistics reports, grand jury reports', 'Persona: ABC-ENFORCEMENT-AUDITOR', 'Attorney General (elected constitutional officer); Cal. Const. Art. V, sec. 13; Key Statute:** Gov. Code 12500-12599.7; Penal Code various; BPC various (charitable trusts: Gov. Code 12580-12599.7); Document Types:** AG opinions, CLETS records, DOJ firearms records (DROS/AFS), charitable trust filings (CT-1/CT-2/RRF-1), Megan''s Law registrations, crime statistics reports, grand jury reports', '', 'AG opinions, CLETS records, DOJ firearms records (DROS/AFS), charitable trust filings (CT-1/CT-2/RRF-1), Megan''s Law registrations, crime statistics reports, grand jury reports');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-00424', 'Persona: DOJ-CHARITABLETRUST-AUDITOR', 'California State Depts Compliance', 'California State Depts', 'Persona: DOJ-CHARITABLETRUST-AUDITOR — Board of Equalization (4 elected members + State Controller ex officio); Cal. Const. Art. XIII; Key Statute:** Rev. & Tax. Code Division 1 (property tax equalization); Cal. Const. Art. XIII, sec. 17-19; Document Types:** Assessment appeals, intercounty equalization findings, utility property assessments, insurance tax assessments, alcoholic beverage tax returns (post-Prop 19 limited scope)', 'Persona: DOJ-CHARITABLETRUST-AUDITOR', 'Board of Equalization (4 elected members + State Controller ex officio); Cal. Const. Art. XIII; Key Statute:** Rev. & Tax. Code Division 1 (property tax equalization); Cal. Const. Art. XIII, sec. 17-19; Document Types:** Assessment appeals, intercounty equalization findings, utility property assessments, insurance tax assessments, alcoholic beverage tax returns (post-Prop 19 limited scope)', '', 'Assessment appeals, intercounty equalization findings, utility property assessments, insurance tax assessments, alcoholic beverage tax returns (post-Prop 19 limited scope)');
