INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01973', 'Equal Employment Opportunity / OFCCP Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Equal Employment Opportunity / OFCCP Compliance Specialist — U.S. Equal Employment Opportunity Commission (EEOC); Office of Federal Contract Compliance Programs (OFCCP); California Civil Rights Department (CRD)', 'Equal Employment Opportunity / OFCCP Compliance Specialist', 'U.S. Equal Employment Opportunity Commission (EEOC); Office of Federal Contract Compliance Programs (OFCCP); California Civil Rights Department (CRD)', 'Title VII of the Civil Rights Act (42 USC 2000e); Executive Order 11246 (federal contractor affirmative action); 41 CFR Parts 60-1 through 60-741 (OFCCP regulations); Cal. Gov. Code 12940-12951 (FEHA employment discrimination); 29 CFR Part 1602 (EEO-1 reporting requirements); VEVRAA (38 USC 4212); Section 503 of the Rehabilitation Act (29 USC 793); 41 CFR 60-300 (VETS-4212 filing requirements)', 'Job posting compliance documents, application/resume screening compliance, EEO-1 reporting documents, VETS-4212 reporting, affirmative action plan documents (OFCCP), pay equity audit documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01974', 'Consumer Reporting Compliance Specialist (FCRA/ICRAA)', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Consumer Reporting Compliance Specialist (FCRA/ICRAA) — Federal Trade Commission (FTC); Consumer Financial Protection Bureau (CFPB); California Department of Justice (for ICRAA)', 'Consumer Reporting Compliance Specialist (FCRA/ICRAA)', 'Federal Trade Commission (FTC); Consumer Financial Protection Bureau (CFPB); California Department of Justice (for ICRAA)', 'Fair Credit Reporting Act (15 USC 1681 et seq.); 16 CFR Part 698 (FTC FCRA rules); Cal. Civ. Code 1785.1-1785.36 (Consumer Credit Reporting Agencies Act); Cal. Civ. Code 1786-1786.60 (Investigative Consumer Reporting Agencies Act / ICRAA); Cal. Lab. Code 432.7 (restrictions on arrest/conviction records); Cal. Gov. Code 12952 (Fair Chance Act / Ban the Box); EEOC Enforcement Guidance on arrest/conviction records (2012, updated)', 'Background check compliance documents (FCRA, Ban the Box, state laws), pre-employment drug testing documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01975', 'Employment Eligibility Verification Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Employment Eligibility Verification Specialist — U.S. Citizenship and Immigration Services (USCIS); Immigration and Customs Enforcement (ICE); U.S. Department of Justice, Immigrant and Employee Rights Section (IER)', 'Employment Eligibility Verification Specialist', 'U.S. Citizenship and Immigration Services (USCIS); Immigration and Customs Enforcement (ICE); U.S. Department of Justice, Immigrant and Employee Rights Section (IER)', 'Immigration and Nationality Act (8 USC 1324a -- employer sanctions); 8 CFR 274a.2 (Form I-9 requirements); E-Verify MOU and federal contractor E-Verify requirements (FAR 52.222-54); INA anti-discrimination provisions (8 USC 1324b); Cal. Lab. Code 1019 (restrictions on employer immigration-related actions); Cal. Lab. Code 1019.1 (immigration-related unfair practices); Cal. Gov. Code 7285 (California Values Act applicability to employers)', 'I-9 employment eligibility verification, E-Verify documents, new hire reporting documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01976', 'Employment Offer / Agreement Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Employment Offer / Agreement Compliance Specialist — California Labor Commissioner (DLSE); EEOC; State taxing authorities', 'Employment Offer / Agreement Compliance Specialist', 'California Labor Commissioner (DLSE); EEOC; State taxing authorities', 'Cal. Lab. Code 2922 (at-will employment); Cal. Lab. Code 432.3 (salary history ban); Cal. Lab. Code 1197.5 (Equal Pay Act); SB 1162 (Cal. Lab. Code 432.3(c) -- pay scale disclosure in job postings); Cal. Gov. Code 12940 (FEHA -- offer contingencies); Cal. Lab. Code 2810.5 (notice to employee at time of hire); applicable city/county fair chance and pay transparency ordinances (SF, LA, NYC equivalents)', 'Offer letter/employment agreement documents, non-compete/non-solicitation documents, arbitration agreement documents, employee invention assignment documents, trade secret protection documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01977', 'Personnel Records and Privacy Compliance Manager', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Personnel Records and Privacy Compliance Manager — California Labor Commissioner (DLSE); California Attorney General (CCPA enforcement); EEOC', 'Personnel Records and Privacy Compliance Manager', 'California Labor Commissioner (DLSE); California Attorney General (CCPA enforcement); EEOC', 'Cal. Lab. Code 1198.5 (employee right to inspect personnel file within 30 days; employer must make available for inspection or provide copy); Cal. Lab. Code 432 (employee right to copy of signed documents); Cal. Civ. Code 1798.100-1798.199 (CCPA/CPRA -- employee data as of Jan 1, 2023); Cal. Lab. Code 226(c) (pay record retention 3 years); 29 CFR 1602.14 (EEOC personnel record retention -- 1 year from separation); Cal. Gov. Code 12946 (FEHA -- 4 years retention); Cal. Lab. Code 1174 (payroll records 3 years)', 'Personnel file compliance (state laws), employee privacy documents, employee monitoring disclosure documents, social media policy compliance, remote work/telecommuting agreements');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01978', 'Workplace Policy and Handbook Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Workplace Policy and Handbook Compliance Specialist — California DLSE; EEOC; National Labor Relations Board (NLRB); California CRD', 'Workplace Policy and Handbook Compliance Specialist', 'California DLSE; EEOC; National Labor Relations Board (NLRB); California CRD', 'Cal. Lab. Code 246 (paid sick leave policy); Cal. Gov. Code 12950 (FEHA poster/policy requirements); Cal. Gov. Code 12950.1 (sexual harassment prevention policy); SB 553 (Cal. Lab. Code 6401.9 -- workplace violence prevention plan required in handbook context); NLRA Section 7 (29 USC 157 -- handbook policies must not chill protected concerted activity per NLRB); Cal. Lab. Code 1102.5 (whistleblower policy); Cal. Lab. Code 98.6 (retaliation prohibition); Cal. Lab. Code 230-230.8 (leave rights disclosures); OSHA poster requirements; Cal. Lab. Code 2810.5 (wage theft prevention notice)', 'Employee handbook/policy documents, social media policy compliance, remote work/telecommuting agreements, employee monitoring disclosure documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01979', 'Performance Evaluation and Corrective Action Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Performance Evaluation and Corrective Action Compliance Specialist — EEOC; California CRD; DLSE (for wage implications of performance-based pay)', 'Performance Evaluation and Corrective Action Compliance Specialist', 'EEOC; California CRD; DLSE (for wage implications of performance-based pay)', 'Title VII / FEHA (performance systems must not have disparate impact -- Griggs v. Duke Power, 401 US 424 (1971)); Cal. Gov. Code 12940(a) (discrimination in terms/conditions of employment includes evaluations); ADA/FEHA interactive process triggered when performance issues may relate to disability; 29 CFR 1607 (Uniform Guidelines on Employee Selection Procedures -- applies to performance evaluations used for employment decisions); Cal. Lab. Code 1102.5 (performance actions cannot constitute retaliation for protected activity)', 'Performance evaluation documents, performance improvement plan (PIP) documents, progressive discipline documents, promotion/demotion documents, transfer documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01980', 'Internal Investigations Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Internal Investigations Compliance Specialist — EEOC; California CRD; DLSE; Cal-OSHA (for safety-related investigations)', 'Internal Investigations Compliance Specialist', 'EEOC; California CRD; DLSE; Cal-OSHA (for safety-related investigations)', 'Cal. Gov. Code 12940(k) (employer duty to investigate harassment/discrimination complaints); Cotran v. Rollins Hudig Hall International (1998) 17 Cal.4th 93 (good faith investigation standard for termination); Silva v. Lucky Stores (1998) 65 Cal.App.4th 256 (investigation methodology); Cal. Lab. Code 1102.5 (whistleblower investigation obligations); Sarbanes-Oxley 806 (18 USC 1514A -- whistleblower for public companies); Cal. Gov. Code 8547-8547.12 (California Whistleblower Protection Act -- public employers); EEOC Enforcement Guidance on Vicarious Employer Liability (1999)', 'Workplace investigation reports, whistleblower investigation documents, ethics investigation documents, code of conduct violation investigation documents, workplace bullying investigation documents, conflict of interest disclosure documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01981', 'Workforce Reduction and WARN Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Workforce Reduction and WARN Compliance Specialist — U.S. Department of Labor (DOL); California Employment Development Department (EDD); DLSE', 'Workforce Reduction and WARN Compliance Specialist', 'U.S. Department of Labor (DOL); California Employment Development Department (EDD); DLSE', 'WARN Act (29 USC 2101-2109); 20 CFR Part 639 (WARN regulations); Cal. Lab. Code 1400-1408 (California WARN Act -- broader than federal: 75 employees, no exemptions for natural disaster or faltering company); Cal. Lab. Code 1401 (60-day written notice to affected employees, EDD, and local workforce investment board); Cal. Lab. Code 1402 (penalties: back pay and benefits for each day of violation); OWBPA (29 USC 626(f) -- Older Workers Benefit Protection Act for RIF releases involving 40+ employees)', 'Reduction in force (RIF) documents, WARN Act notification documents, separation agreement/severance documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01982', 'Unemployment Insurance Response and Separation Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Unemployment Insurance Response and Separation Compliance Specialist — California Employment Development Department (EDD); U.S. Department of Labor (DOL)', 'Unemployment Insurance Response and Separation Compliance Specialist', 'California Employment Development Department (EDD); U.S. Department of Labor (DOL)', 'Cal. Unemp. Ins. Code 1026-1034 (employer registration and reporting); Cal. Unemp. Ins. Code 1085-1089 (employer contributions); Cal. Unemp. Ins. Code 1256-1256.8 (disqualification for misconduct -- employer burden of proof); Cal. Unemp. Ins. Code 1030 (employer response to UI claim within 10 days); Cal. Unemp. Ins. Code 1327 (determination process); FUTA (26 USC 3301-3311); 20 CFR Part 603 (confidentiality of UI information)', 'Exit interview documents, unemployment insurance response documents, employment verification documents, separation agreement/severance documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01983', 'Attorney -- Post-Employment Restrictive Covenants', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Attorney -- Post-Employment Restrictive Covenants — State Bar of California; California Legislature (strong public policy against restraints)', 'Attorney -- Post-Employment Restrictive Covenants', 'State Bar of California; California Legislature (strong public policy against restraints)', 'Cal. Bus. & Prof. Code 16600 (void restraint on engaging in lawful profession -- California near-total ban on non-competes); Cal. Bus. & Prof. Code 16600.5 (AB 1076 -- codified Edwards v. Arthur Andersen, no non-compete even with consideration); SB 699 (Cal. Bus. & Prof. Code 16600.5(a) -- employer cannot enforce out-of-state non-compete against California employee); Cal. Lab. Code 2870-2872 (employee invention assignment limitations -- cannot assign inventions made entirely on own time without employer resources); Cal. Civ. Code 3426-3426.11 (Uniform Trade Secrets Act -- only permissible post-employment restriction is trade secret protection); Defend Trade Secrets Act (18 USC 1836)', 'Non-compete/non-solicitation documents, trade secret protection documents, employee invention assignment documents, arbitration agreement documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01984', 'Pay Equity and Compensation Compliance Analyst', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Pay Equity and Compensation Compliance Analyst — California CRD; DLSE; EEOC; OFCCP', 'Pay Equity and Compensation Compliance Analyst', 'California CRD; DLSE; EEOC; OFCCP', 'Cal. Lab. Code 1197.5 (California Equal Pay Act -- equal pay for substantially similar work); Cal. Lab. Code 432.3 (salary history ban); SB 1162 (pay data reporting to CRD for 100+ employees, pay scale disclosure in job postings for 15+ employees); Equal Pay Act of 1963 (29 USC 206(d)); Title VII (42 USC 2000e -- compensation discrimination); Lilly Ledbetter Fair Pay Act (42 USC 2000e-5(e)(3)); 41 CFR 60-2.17(b)(3) (OFCCP compensation analysis for contractors); Executive Order 14069 (advancing pay equity for federal workforce/contractors)', 'Pay equity audit documents, salary history ban compliance, job posting compliance documents (pay transparency component)');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01985', 'Payroll Operations and Wage Compliance Manager', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Payroll Operations and Wage Compliance Manager — California DLSE; IRS; California EDD; U.S. Department of Labor WHD', 'Payroll Operations and Wage Compliance Manager', 'California DLSE; IRS; California EDD; U.S. Department of Labor WHD', 'Cal. Lab. Code 200-244 (payment of wages); Cal. Lab. Code 226 (itemized wage statements -- 9 required elements); Cal. Lab. Code 204 (semi-monthly pay frequency); Cal. Lab. Code 510 (daily overtime -- 8 hours/day, 12 hours/day double time, 7th consecutive day); FLSA (29 USC 201-219); 29 CFR Part 778 (overtime computation); Cal. Lab. Code 1194 (private right of action for unpaid wages); Cal. Lab. Code 558.1 (individual liability for wage theft); Cal. Lab. Code 2810.5 (wage theft prevention notice at hire)', 'Payroll register documents, pay stub/wage statement compliance, overtime calculation documents, minimum wage compliance');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01986', 'Wage and Hour Exemption Classification Analyst', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Wage and Hour Exemption Classification Analyst — U.S. Department of Labor WHD; California DLSE; California CRD', 'Wage and Hour Exemption Classification Analyst', 'U.S. Department of Labor WHD; California DLSE; California CRD', 'FLSA (29 USC 213(a)(1) -- white collar exemptions); 29 CFR Part 541 (executive, administrative, professional, computer, outside sales exemptions); Cal. Lab. Code 515 (California exemption requirements -- salary basis AND duties test); IWC Wage Orders 1-17 (industry-specific overtime and exemption rules); Cal. Lab. Code 515.5 (computer professional exemption -- higher salary threshold than federal); ABC test for independent contractor classification (Cal. Lab. Code 2775 -- AB 5); Dynamex Operations West v. Superior Court (2018) 4 Cal.5th 903', 'Exempt/non-exempt classification documents, commission agreement documents, tip credit/tip pool documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01987', 'Payroll Tax and Regulatory Reporting Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Payroll Tax and Regulatory Reporting Specialist — Internal Revenue Service (IRS); California EDD; California Franchise Tax Board (FTB); Social Security Administration (SSA)', 'Payroll Tax and Regulatory Reporting Specialist', 'Internal Revenue Service (IRS); California EDD; California Franchise Tax Board (FTB); Social Security Administration (SSA)', 'IRC 3101-3128 (FICA -- Social Security and Medicare); IRC 3301-3311 (FUTA); IRC 3401-3406 (federal income tax withholding); Cal. Unemp. Ins. Code 13009-13028 (California personal income tax withholding); Cal. Unemp. Ins. Code 976-984 (SDI contributions); Cal. Unemp. Ins. Code 1085-1089 (SUI/ETT rates); 26 CFR 31.6011(a)-1 through -5 (employment tax return requirements); IRC 6721-6723 (information return penalties)', 'Form W-4 documents, state withholding documents, payroll tax deposit documents, Form 941 quarterly returns, Form W-2 preparation, Form 1099 preparation, new hire reporting documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01988', 'Involuntary Wage Withholding Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Involuntary Wage Withholding Compliance Specialist — U.S. Department of Labor; California DLSE; California Franchise Tax Board; state and federal courts', 'Involuntary Wage Withholding Compliance Specialist', 'U.S. Department of Labor; California DLSE; California Franchise Tax Board; state and federal courts', 'Consumer Credit Protection Act Title III (15 USC 1671-1677 -- maximum garnishment 25% of disposable earnings or amount exceeding 30x federal minimum wage); Cal. Code Civ. Proc. 706.010-706.154 (earnings withholding orders); Cal. Fam. Code 5200-5270 (child/spousal support withholding); 42 USC 666(b) (federal child support income withholding); IRS IRC 6331 (federal tax levies); Cal. Rev. & Tax Code 18817 (FTB tax levies); 20 CFR 870 (federal student loan garnishment -- limited by recent rules); priority of garnishments: child support first, then tax levies, then creditor garnishments', 'Garnishment/levy processing documents, child support withholding documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01989', 'Attorney -- ERISA and Employee Benefits Law', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Attorney -- ERISA and Employee Benefits Law — U.S. Department of Labor Employee Benefits Security Administration (EBSA); IRS (plan qualification); Pension Benefit Guaranty Corporation (PBGC); State Bar of California', 'Attorney -- ERISA and Employee Benefits Law', 'U.S. Department of Labor Employee Benefits Security Administration (EBSA); IRS (plan qualification); Pension Benefit Guaranty Corporation (PBGC); State Bar of California', 'ERISA (29 USC 1001-1461); IRC 401(a) (qualified plan requirements); IRC 401(k) (cash or deferred arrangements); IRC 403(b) (tax-sheltered annuities); IRC 457(b) (deferred compensation -- governmental/tax-exempt); 29 CFR Part 2520 (reporting and disclosure); 29 CFR Part 2550 (fiduciary responsibility); 29 CFR Part 2560 (claims procedure); ERISA 404(a) (prudent expert standard); ERISA 406-408 (prohibited transactions); ERISA 502 (enforcement -- civil actions by participants, beneficiaries, fiduciaries, DOL)', 'ERISA compliance documents, Form 5500 annual reports, summary plan description (SPD) documents, summary of material modifications, 401(k)/403(b) plan documents, pension plan documents, fiduciary responsibility documents, prohibited transaction documents, plan audit documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01990', 'Pension Benefit Guaranty Corporation Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Pension Benefit Guaranty Corporation Compliance Specialist — Pension Benefit Guaranty Corporation (PBGC); IRS Employee Plans', 'Pension Benefit Guaranty Corporation Compliance Specialist', 'Pension Benefit Guaranty Corporation (PBGC); IRS Employee Plans', 'ERISA Title IV (29 USC 1301-1461 -- plan termination insurance); PBGC premium regulations (29 CFR Part 4006 -- flat-rate and variable-rate premiums); ERISA 4010 (reporting for underfunded plans); ERISA 4041-4041A (standard and distress termination procedures); ERISA 4043 (reportable events); IRC 430 (minimum funding standards for single-employer plans); IRC 432 (multiemployer plan funding rules); Pension Protection Act of 2006 (funding reform); SECURE Act 2.0 (2022 -- updated funding and disclosure requirements)', 'PBGC filing documents, pension plan documents, plan audit documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01991', 'COBRA and Continuation Coverage Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'COBRA and Continuation Coverage Compliance Administrator — U.S. Department of Labor EBSA; IRS; California DMHC and CDI (Cal-COBRA)', 'COBRA and Continuation Coverage Compliance Administrator', 'U.S. Department of Labor EBSA; IRS; California DMHC and CDI (Cal-COBRA)', 'COBRA (26 USC 4980B; 29 USC 1161-1169; 42 USC 300bb-1 to 300bb-8); 29 CFR Part 2590 (DOL COBRA regulations); Cal. Health & Safety Code 1373.6 and Cal. Ins. Code 10128.50 (Cal-COBRA -- extends to employers with 2-19 employees and provides additional 36 months after federal COBRA exhaustion); Cal. Gov. Code 22850-22856 (CalPERS COBRA provisions); DOL Model COBRA Notices (updated)', 'COBRA administration documents, benefits enrollment documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01992', 'Group Health Plan Privacy and Portability Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Group Health Plan Privacy and Portability Compliance Administrator — U.S. Department of Health and Human Services OCR (HIPAA Privacy/Security); DOL EBSA; IRS; California DMHC; California CDI', 'Group Health Plan Privacy and Portability Compliance Administrator', 'U.S. Department of Health and Human Services OCR (HIPAA Privacy/Security); DOL EBSA; IRS; California DMHC; California CDI', 'HIPAA Privacy Rule (45 CFR Parts 160, 164 Subpart E); HIPAA Security Rule (45 CFR Part 164 Subpart C); HIPAA Portability (42 USC 1320d et seq.); ACA (42 USC 18001 et seq.); Mental Health Parity and Addiction Equity Act (29 USC 1185a); Newborns'' and Mothers'' Health Protection Act (29 USC 1185); Women''s Health and Cancer Rights Act (29 USC 1185b); Cal. Health & Safety Code 1340-1399.800 (Knox-Keene Act); Cal. Ins. Code 10110-10192 (health insurance regulations); Consolidated Appropriations Act 2021 (surprise billing, transparency requirements)', 'HIPAA portability certificates, FSA/HSA/HRA administration documents, benefits enrollment documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01993', 'QDRO Review and Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'QDRO Review and Compliance Administrator — U.S. Department of Labor EBSA; IRS; State family courts', 'QDRO Review and Compliance Administrator', 'U.S. Department of Labor EBSA; IRS; State family courts', 'ERISA 206(d)(3) (29 USC 1056(d)(3) -- QDRO exception to anti-alienation rule); IRC 414(p) (definition of QDRO); 29 CFR 2530.206 (DOL QDRO guidance); Cal. Fam. Code 2060 (joinder of pension plan in dissolution); Cal. Fam. Code 2610 (community property division of retirement benefits); ERISA 206(d)(3)(G) (plan administrator determination procedures -- 18-month segregation period)', 'Qualified domestic relations order (QDRO) documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01994', 'Nonqualified Deferred Compensation Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Nonqualified Deferred Compensation Compliance Specialist — Internal Revenue Service; SEC (for publicly traded companies); DOL', 'Nonqualified Deferred Compensation Compliance Specialist', 'Internal Revenue Service; SEC (for publicly traded companies); DOL', 'IRC 409A (nonqualified deferred compensation rules); 26 CFR 1.409A-1 through 1.409A-6 (Treasury regulations); IRC 457A (deferred compensation of certain tax-indifferent parties); Notice 2008-113 (correction program for 409A operational failures); IRC 3121(v)(2) (FICA timing for NQDC); Cal. Rev. & Tax Code 17501 (California conformity to 409A); SEC Rule 10b5-1 (insider trading safe harbor for equity award sales); Dodd-Frank 954 (clawback of erroneously awarded compensation -- SEC final rule 2022)', 'Deferred compensation documents (409A), equity compensation documents (stock options, RSUs), bonus/incentive plan documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01995', 'Leave Administration and Accommodation Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Leave Administration and Accommodation Compliance Specialist — U.S. Department of Labor WHD (FMLA); California CRD (CFRA/PDL); EEOC (ADA)', 'Leave Administration and Accommodation Compliance Specialist', 'U.S. Department of Labor WHD (FMLA); California CRD (CFRA/PDL); EEOC (ADA)', 'FMLA (29 USC 2601-2654); 29 CFR Part 825 (FMLA regulations); Cal. Gov. Code 12945-12945.6 (CFRA -- California Family Rights Act, expanded beyond FMLA); Cal. Gov. Code 12945 (Pregnancy Disability Leave -- up to 4 months, no minimum employee count for PDL); Cal. Lab. Code 233 (kin care -- use sick leave for family); Cal. Lab. Code 246 (paid sick leave -- 5 days/40 hours minimum); Cal. Gov. Code 12940(m)-(n) (reasonable accommodation/interactive process); ADA (42 USC 12111-12117); Cal. Lab. Code 230-230.8 (crime victim, domestic violence, jury duty, school activities, military leave)', 'Leave administration documents (FMLA/CFRA/PDL/ADA), reasonable accommodation interactive process documents, pregnancy accommodation documents, religious accommodation documents, lactation accommodation documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01996', 'Harassment Prevention Training Program Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Harassment Prevention Training Program Compliance Administrator — California CRD (formerly DFEH); EEOC', 'Harassment Prevention Training Program Compliance Administrator', 'California CRD (formerly DFEH); EEOC', 'Cal. Gov. Code 12950.1 (SB 1343 -- mandatory sexual harassment prevention training); 2 CCR 11024 (training requirements regulations); Cal. Gov. Code 12950 (FEHA harassment poster); EEOC Enforcement Guidance on Vicarious Employer Liability for Unlawful Harassment (1999); Cal. Gov. Code 12940(j) (harassment prohibition and employer liability); Cal. Gov. Code 12940(k) (duty to prevent harassment); AB 1825 (original 2-hour supervisor training mandate, now expanded by SB 1343)', 'Sexual harassment prevention training documents (SB 1343), anti-discrimination training documents, bystander intervention training documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01997', 'Workplace Violence Prevention Program Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Workplace Violence Prevention Program Administrator — Cal/OSHA; California Division of Occupational Safety and Health (DOSH)', 'Workplace Violence Prevention Program Administrator', 'Cal/OSHA; California Division of Occupational Safety and Health (DOSH)', 'SB 553 (Cal. Lab. Code 6401.9 -- Workplace Violence Prevention Plan required for nearly all California employers effective July 1, 2024); 8 CCR 3342 (healthcare workplace violence -- existing Cal/OSHA standard); Cal. Lab. Code 6401.7 (IIPP -- Injury and Illness Prevention Program, violence prevention as component); Cal. Penal Code 11160-11163.6 (reporting violent injuries); Cal. Code Regs. Title 8, new Section 3343 (SB 553 implementing regulations); OSHA General Duty Clause (29 USC 654(a)(1) -- federal parallel)', 'Workplace violence prevention plan documents (SB 553), threat assessment documents, active shooter preparedness documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01998', 'DEI Program Compliance and Reporting Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'DEI Program Compliance and Reporting Specialist — EEOC; OFCCP; California CRD; SEC (for publicly traded company ESG reporting)', 'DEI Program Compliance and Reporting Specialist', 'EEOC; OFCCP; California CRD; SEC (for publicly traded company ESG reporting)', 'Title VII (42 USC 2000e -- voluntary affirmative action programs must satisfy Weber/Johnson framework); Executive Order 11246 (affirmative action for federal contractors); EEOC Guidelines on Affirmative Action (29 CFR Part 1608 -- safe harbor for lawful voluntary programs); Cal. Corp. Code 301.3-301.4 (board diversity -- SB 826 enjoined/Crest v. Padilla but compliance culture persists); SEC Regulation S-K Item 101(c) (human capital disclosures); Nasdaq Board Diversity Rules (Listing Rule 5605(f) -- vacated by 5th Circuit 2024 but still voluntary best practice); Cal. Gov. Code 12940 (DEI programs cannot create reverse discrimination claims)', 'Diversity/equity/inclusion (DEI) program documents, employee resource group (ERG) documents, unconscious bias training documents, workplace culture survey documents, employee engagement survey documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-01999', 'EAP and Behavioral Health Benefit Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'EAP and Behavioral Health Benefit Compliance Administrator — California DMHC; California BBS (Board of Behavioral Sciences); SAMHSA (federal guidance); DOL EBSA (if EAP is ERISA-covered)', 'EAP and Behavioral Health Benefit Compliance Administrator', 'California DMHC; California BBS (Board of Behavioral Sciences); SAMHSA (federal guidance); DOL EBSA (if EAP is ERISA-covered)', 'Cal. Health & Safety Code 1340 et seq. (Knox-Keene -- if EAP provides healthcare); HIPAA Privacy Rule (45 CFR 164 -- if EAP handles PHI); Mental Health Parity and Addiction Equity Act (29 USC 1185a -- if EAP provides mental health benefits beyond referral); Cal. Welf. & Inst. Code 5150 (mandatory reporting when danger to self/others); Cal. Bus. & Prof. Code 2290.5 (telehealth requirements for virtual EAP); ERISA (29 USC 1001 -- coverage depends on whether EAP is benefits-providing or referral-only); 42 CFR Part 2 (substance use disorder records confidentiality)', 'Employee assistance program (EAP) documents, stay interview documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-02000', 'Gender Identity and Expression Workplace Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Gender Identity and Expression Workplace Compliance Specialist — California CRD; EEOC; Cal/OSHA (facilities)', 'Gender Identity and Expression Workplace Compliance Specialist', 'California CRD; EEOC; Cal/OSHA (facilities)', 'Cal. Gov. Code 12940 (FEHA prohibits discrimination based on gender identity, gender expression, and sexual orientation); Cal. Gov. Code 12949 (dress code/grooming standards cannot enforce gender stereotypes); 2 CCR 11030-11031 (CRD transgender employee regulations); Cal. Gov. Code 12926(r)(2) (sex includes gender identity and gender expression); Bostock v. Clayton County, 590 US ___ (2020) (Title VII covers gender identity and sexual orientation); EEOC Strategic Enforcement Plan; Cal. Educ. Code 221.5 (educational employment contexts); Cal. Health & Safety Code 103430 (name/gender change records)', 'Gender transition workplace documents, reasonable accommodation interactive process documents (identity-related), employee privacy documents');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-02001', 'Labor Relations and Collective Bargaining Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Labor Relations and Collective Bargaining Compliance Specialist — National Labor Relations Board (NLRB); California PERB (Public Employment Relations Board -- public sector)', 'Labor Relations and Collective Bargaining Compliance Specialist', 'National Labor Relations Board (NLRB); California PERB (Public Employment Relations Board -- public sector)', 'NLRA (29 USC 151-169); NLRA Section 7 (employee rights to organize, bargain collectively, engage in concerted activity); NLRA Section 8(a) (employer unfair labor practices -- interference, domination, discrimination, retaliation, refusal to bargain); NLRA Section 8(b) (union unfair labor practices); 29 CFR Parts 100-103 (NLRB rules); Cal. Gov. Code 3500-3511 (Meyers-Milias-Brown Act -- local public employees); Cal. Gov. Code 3512-3524 (Dills Act -- state employees); Cal. Gov. Code 3540-3549.3 (EERA -- educational employees); NLRB v. Gissel Packing Co., 395 US 575 (1969) (bargaining orders); Cemex Construction Materials Pacific, 372 NLRB No. 130 (2023) (new recognition framework)', 'Union avoidance/labor relations documents, gift/entertainment policy documents (union context)');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-02002', 'Corporate Ethics and Conflict of Interest Compliance Officer', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Corporate Ethics and Conflict of Interest Compliance Officer — SEC (publicly traded); DOJ Criminal Division (FCPA/anti-corruption); California Attorney General (nonprofit governance); Professional licensing boards', 'Corporate Ethics and Conflict of Interest Compliance Officer', 'SEC (publicly traded); DOJ Criminal Division (FCPA/anti-corruption); California Attorney General (nonprofit governance); Professional licensing boards', 'Sarbanes-Oxley Act Section 301 (audit committee independence), Section 406 (code of ethics for senior financial officers), Section 806 (whistleblower protection); Dodd-Frank Act Section 922 (SEC whistleblower awards); Cal. Corp. Code 310 (director conflict of interest transactions); Cal. Corp. Code 5233 (nonprofit self-dealing); Cal. Lab. Code 1102.5 (California whistleblower protection); Cal. Gov. Code 1090-1099 (conflict of interest -- public officials); Cal. Gov. Code 81000-91014 (Political Reform Act -- Form 700); FCPA (15 USC 78dd-1 to -3)', 'Ethics investigation documents, conflict of interest disclosure documents, gift/entertainment policy documents, code of conduct violation investigation documents, whistleblower investigation documents');
