INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-02748', 'Persona C.8.2: USPS Inspection Service Administrative Compliance Officer', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.8.2: USPS Inspection Service Administrative Compliance Officer — USPIS', 'Persona C.8.2: USPS Inspection Service Administrative Compliance Officer', 'USPIS', ':; 39 USC § 3005 (false representations — administrative proceedings); 39 USC § 3007 (detention of mail — temporary restraining order); 39 USC § 3008 (prohibitory orders — sexually explicit mail); 39 USC § 3010 (mailing of sexually explicit material to minors); 39 USC § 3011 (judicial enforcement); 39 CFR Part 952 (Administrative Proceedings); 39 CFR Part 959 (false representation/lottery proceedings); 39 CFR § 233.1 (USPIS general authority); Administrative Procedure Act (5 USC § 551 et seq.)', 'Administrative complaint filings (§ 3005), temporary restraining orders (§ 3007), prohibitory order applications (§ 3008), hearing records, evidence files, witness statements, legal analysis memoranda, case disposition orders, appeal records, mail detention records, consent agreements, civil penalty assessments');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-02749', 'Persona C.8.3: Newspaper/Periodical Mail Permit Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.8.3: Newspaper/Periodical Mail Permit Specialist — USPS', 'Persona C.8.3: Newspaper/Periodical Mail Permit Specialist', 'USPS', ':; 39 USC § 3626 (periodical class postage rates); USPS DMM § 207 (Periodicals — eligibility and standards); USPS PS Form 3526 (Statement of Ownership, Management, and Circulation); 39 CFR § 111.3 (Periodicals classification); USPS Publication 501 (Media Mail and Library Rate eligibility); First Amendment considerations (publisher/periodical access to mail system); USPS DMM § 707 (Periodicals preparation)', 'Periodicals authorization applications, PS Form 3526 (Statement of Ownership — annual), circulation verification records, advertising ratio calculations, publication frequency documentation, subscriber list records, pending Periodicals applications, content eligibility review records, postage payment records, publication sample copies');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-02750', 'Persona C.9.1: Courier/Messenger Service License Compliance Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.9.1: Courier/Messenger Service License Compliance Manager — State/local licensing authorities; FMCSA (if interstate)', 'Persona C.9.1: Courier/Messenger Service License Compliance Manager', 'State/local licensing authorities; FMCSA (if interstate)', ':; Cal. Bus. & Prof. Code § 3100-3105 (no specific courier licensing in CA — general business license); Cal. Veh. Code § 34500 et seq. (commercial vehicle safety — if applicable); 49 USC § 13501 (federal motor carrier jurisdiction — interstate); 49 CFR Part 390 (Federal Motor Carrier Safety Regulations — if CMV); Cal. Lab. Code § 2775 (ABC test — worker classification); Local business license requirements; Cal. Ins. Code § 11580 (vehicle insurance requirements); 49 CFR Part 387 (minimum insurance for motor carriers)', 'Business license records, vehicle insurance certificates, FMCSA operating authority (if interstate), USDOT registration, driver qualification files, vehicle inspection reports, maintenance records, worker classification documentation, delivery records, customer contracts, route documentation');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, document_types) VALUES ('citizen-02751', 'Persona C.9.2: Overnight/Express Carrier Regulatory Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.9.2: Overnight/Express Carrier Regulatory Compliance Specialist — FAA (air transport); FMCSA (ground transport); DOT; TSA (security)', 'Persona C.9.2: Overnight/Express Carrier Regulatory Compliance Specialist', 'FAA (air transport); FMCSA (ground transport); DOT; TSA (security)', ':; 49 USC § 41101 (air carrier certificate requirement); 14 CFR Part 121 (operating requirements — domestic air carriers); 14 CFR Part 135 (commuter and on-demand operations); 49 USC § 44901 (TSA screening requirements); 49 CFR Part 1548 (indirect air carrier security); 49 CFR Part 172 (hazmat transportation); 49 USC § 14706 (Carmack Amendment — ground segment liability); 49 USC § 40120 (FAA preemption of state regulation of air carriers); Montreal Convention (international air carriage liability); Warsaw Convention (legacy international air carriage)', 'FAA air carrier certificates, TSA security programs, FMCSA operating authority, hazmat transportation documents, known shipper records, claims processing records (Carmack/Montreal Convention), declaration of value records, security screening records, delivery tracking records, customs documentation (international), insurance certificates');
